export interface VideoSettings {
  brightness: number;
  contrast: number;
  saturation: number;
  blur: number;
  vignette: number;
  faceLight: number;
}

export interface VirtualBackground {
  enabled: boolean;
  type: 'none' | 'blur' | 'image' | 'color';
  value: string;
  blurStrength: number;
}

export interface VideoState extends VideoSettings {
  virtualBackground: VirtualBackground;
  selectedDeviceId: string;
  devices: MediaDeviceInfo[];
  isMirrored: boolean;
  aspectRatio: '16:9' | '9:16' | '4:3' | '1:1';
}

export const DEFAULT_VIDEO_SETTINGS: VideoSettings = {
  brightness: 100,
  contrast: 100,
  saturation: 100,
  blur: 0,
  vignette: 20,
  faceLight: 0,
};

export const DEFAULT_VIRTUAL_BACKGROUND: VirtualBackground = {
  enabled: false,
  type: 'none',
  value: '',
  blurStrength: 10,
};
