import React from 'react';
import { clsx } from 'clsx';

export interface ToggleProps {
  label?: string;
  checked: boolean;
  onChange: (checked: boolean) => void;
  disabled?: boolean;
  size?: 'sm' | 'md' | 'lg';
  className?: string;
}

export const Toggle: React.FC<ToggleProps> = ({
  label,
  checked,
  onChange,
  disabled = false,
  size = 'md',
  className,
}) => {
  const sizes = {
    sm: {
      track: 'w-8 h-4',
      thumb: 'w-3 h-3',
      translate: 'translate-x-4',
    },
    md: {
      track: 'w-12 h-6',
      thumb: 'w-4 h-4',
      translate: 'translate-x-6',
    },
    lg: {
      track: 'w-14 h-7',
      thumb: 'w-5 h-5',
      translate: 'translate-x-7',
    },
  };

  const currentSize = sizes[size];

  return (
    <div className={clsx('flex items-center justify-between', className)}>
      {label && <span className="text-sm text-slate-300">{label}</span>}
      <button
        type="button"
        role="switch"
        aria-checked={checked}
        onClick={() => !disabled && onChange(!checked)}
        disabled={disabled}
        className={clsx(
          currentSize.track,
          'rounded-full p-1 transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 focus:ring-offset-studio-bg',
          checked ? 'bg-blue-600' : 'bg-slate-700',
          disabled && 'opacity-50 cursor-not-allowed'
        )}
      >
        <div
          className={clsx(
            currentSize.thumb,
            'bg-white rounded-full shadow-md transform transition-transform',
            checked && currentSize.translate
          )}
        />
      </button>
    </div>
  );
};
