import { useEffect, useRef } from 'react';
import { useRecordingStore, usePrompterStore } from '@/stores';

/**
 * Hook to sync recording state with teleprompter
 * - When recording starts: auto-play teleprompter and reset position
 * - When recording stops: pause teleprompter
 */
export function useRecordingPrompterSync() {
  const isRecording = useRecordingStore((s) => s.isRecording);
  const play = usePrompterStore((s) => s.play);
  const pause = usePrompterStore((s) => s.pause);
  const resetPosition = usePrompterStore((s) => s.resetPosition);

  const prevRecordingRef = useRef(false);

  useEffect(() => {
    // Only trigger on state change, not initial render
    if (prevRecordingRef.current !== isRecording) {
      if (isRecording) {
        // Recording started - reset position and start scrolling
        resetPosition();
        // Small delay to ensure position is reset
        setTimeout(() => {
          play();
        }, 100);
      } else {
        // Recording stopped - pause scrolling
        pause();
      }
      prevRecordingRef.current = isRecording;
    }
  }, [isRecording, play, pause, resetPosition]);
}
