import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';
import { Button } from './Button';

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
  resetKeys?: unknown[];
}

interface State {
  hasError: boolean;
  error: Error | null;
}

export class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
    console.error('ErrorBoundary caught an error:', error, errorInfo);
    this.props.onError?.(error, errorInfo);
  }

  componentDidUpdate(prevProps: Props): void {
    if (this.state.hasError && this.props.resetKeys) {
      const hasChanged = this.props.resetKeys.some(
        (key, index) => key !== prevProps.resetKeys?.[index]
      );
      if (hasChanged) {
        this.reset();
      }
    }
  }

  reset = (): void => {
    this.setState({ hasError: false, error: null });
  };

  render(): ReactNode {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback;
      }

      return (
        <div className="flex flex-col items-center justify-center min-h-[200px] p-8 bg-slate-900 rounded-xl border border-slate-700">
          <AlertTriangle className="w-12 h-12 text-red-500 mb-4" />
          <h3 className="text-lg font-semibold text-white mb-2">
            Что-то пошло не так
          </h3>
          <p className="text-sm text-slate-400 text-center mb-4 max-w-md">
            {this.state.error?.message || 'Произошла непредвиденная ошибка'}
          </p>
          <Button onClick={this.reset} leftIcon={<RefreshCw size={16} />}>
            Попробовать снова
          </Button>
        </div>
      );
    }

    return this.props.children;
  }
}

// Functional wrapper for hooks support
export const withErrorBoundary = <P extends object>(
  WrappedComponent: React.ComponentType<P>,
  errorBoundaryProps?: Omit<Props, 'children'>
) => {
  const WithErrorBoundary = (props: P) => (
    <ErrorBoundary {...errorBoundaryProps}>
      <WrappedComponent {...props} />
    </ErrorBoundary>
  );

  WithErrorBoundary.displayName = `WithErrorBoundary(${
    WrappedComponent.displayName || WrappedComponent.name || 'Component'
  })`;

  return WithErrorBoundary;
};

// Specific error fallbacks
export const CameraErrorFallback: React.FC<{ onRetry?: () => void }> = ({
  onRetry,
}) => (
  <div className="flex flex-col items-center justify-center h-full bg-slate-900 rounded-xl border border-slate-700 p-8">
    <AlertTriangle className="w-16 h-16 text-yellow-500 mb-4" />
    <h3 className="text-lg font-semibold text-white mb-2">Камера недоступна</h3>
    <p className="text-sm text-slate-400 text-center mb-4">
      Пожалуйста, разрешите доступ к камере в настройках браузера
    </p>
    {onRetry && (
      <Button onClick={onRetry} leftIcon={<RefreshCw size={16} />}>
        Повторить попытку
      </Button>
    )}
  </div>
);

