import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { Scene, SceneState } from '@/types';
import { createSceneId } from '@/types';
import { useVideoStore } from './useVideoStore';
import { useAudioStore } from './useAudioStore';
import { useOverlayStore } from './useOverlayStore';
import { usePrompterStore } from './usePrompterStore';

interface SceneActions {
  createScene: (name: string) => Scene;
  duplicateScene: (id: string) => Scene | null;
  updateScene: (id: string, updates: Partial<Scene>) => void;
  deleteScene: (id: string) => void;
  loadScene: (id: string) => void;
  setActiveScene: (id: string | null) => void;
  reorderScenes: (fromIndex: number, toIndex: number) => void;
  saveCurrentToScene: (id: string) => void;
  captureSceneThumbnail: (id: string, thumbnail: string) => void;
}

const initialState: SceneState = {
  scenes: [],
  activeSceneId: null,
};

export const useSceneStore = create<SceneState & SceneActions>()(
  persist(
    (set, get) => ({
      ...initialState,

      createScene: (name) => {
        const videoStore = useVideoStore.getState();
        const audioStore = useAudioStore.getState();
        const overlayStore = useOverlayStore.getState();
        const prompterStore = usePrompterStore.getState();

        const now = Date.now();
        const scene: Scene = {
          id: createSceneId(),
          name,
          thumbnail: null,
          video: {
            brightness: videoStore.brightness,
            contrast: videoStore.contrast,
            saturation: videoStore.saturation,
            blur: videoStore.blur,
            vignette: videoStore.vignette,
            faceLight: videoStore.faceLight,
            virtualBackground: videoStore.virtualBackground,
          },
          audio: {
            gain: audioStore.gain,
            noiseSuppression: audioStore.noiseSuppression,
            echoCancellation: audioStore.echoCancellation,
            autoGainControl: audioStore.autoGainControl,
            lowCut: audioStore.lowCut,
            midBoost: audioStore.midBoost,
            highBoost: audioStore.highBoost,
          },
          overlay: {
            lowerThird: overlayStore.lowerThird,
            ticker: overlayStore.ticker,
            logo: overlayStore.logo,
            subtitles: overlayStore.subtitles,
            ads: overlayStore.ads,
            activeAdId: overlayStore.activeAdId,
          },
          prompter: {
            text: prompterStore.text,
            fontSize: prompterStore.fontSize,
            speed: prompterStore.speed,
            isPlaying: false,
            opacity: prompterStore.opacity,
            mirror: prompterStore.mirror,
            width: prompterStore.width,
            voiceScroll: prompterStore.voiceScroll,
            voiceSensitivity: prompterStore.voiceSensitivity,
          },
          createdAt: now,
          updatedAt: now,
        };

        set((state) => ({
          scenes: [...state.scenes, scene],
          activeSceneId: scene.id,
        }));

        return scene;
      },

      duplicateScene: (id) => {
        const scene = get().scenes.find((s) => s.id === id);
        if (!scene) return null;

        const now = Date.now();
        const newScene: Scene = {
          ...scene,
          id: createSceneId(),
          name: `${scene.name} (копия)`,
          createdAt: now,
          updatedAt: now,
        };

        set((state) => ({
          scenes: [...state.scenes, newScene],
        }));

        return newScene;
      },

      updateScene: (id, updates) =>
        set((state) => ({
          scenes: state.scenes.map((scene) =>
            scene.id === id
              ? { ...scene, ...updates, updatedAt: Date.now() }
              : scene
          ),
        })),

      deleteScene: (id) =>
        set((state) => ({
          scenes: state.scenes.filter((scene) => scene.id !== id),
          activeSceneId: state.activeSceneId === id ? null : state.activeSceneId,
        })),

      loadScene: (id) => {
        const scene = get().scenes.find((s) => s.id === id);
        if (!scene) return;

        const videoStore = useVideoStore.getState();
        const audioStore = useAudioStore.getState();
        const overlayStore = useOverlayStore.getState();
        const prompterStore = usePrompterStore.getState();

        videoStore.updateSettings(scene.video);
        videoStore.updateVirtualBackground(scene.video.virtualBackground);
        audioStore.updateSettings(scene.audio);
        overlayStore.updateLowerThird(scene.overlay.lowerThird);
        overlayStore.updateTicker(scene.overlay.ticker);
        overlayStore.updateLogo(scene.overlay.logo);
        overlayStore.updateSubtitles(scene.overlay.subtitles);
        prompterStore.updateSettings(scene.prompter);

        set({ activeSceneId: id });
      },

      setActiveScene: (id) =>
        set({ activeSceneId: id }),

      reorderScenes: (fromIndex, toIndex) =>
        set((state) => {
          const scenes = [...state.scenes];
          const [removed] = scenes.splice(fromIndex, 1);
          scenes.splice(toIndex, 0, removed);
          return { scenes };
        }),

      saveCurrentToScene: (id) => {
        const videoStore = useVideoStore.getState();
        const audioStore = useAudioStore.getState();
        const overlayStore = useOverlayStore.getState();
        const prompterStore = usePrompterStore.getState();

        set((state) => ({
          scenes: state.scenes.map((scene) =>
            scene.id === id
              ? {
                  ...scene,
                  video: {
                    brightness: videoStore.brightness,
                    contrast: videoStore.contrast,
                    saturation: videoStore.saturation,
                    blur: videoStore.blur,
                    vignette: videoStore.vignette,
                    faceLight: videoStore.faceLight,
                    virtualBackground: videoStore.virtualBackground,
                  },
                  audio: {
                    gain: audioStore.gain,
                    noiseSuppression: audioStore.noiseSuppression,
                    echoCancellation: audioStore.echoCancellation,
                    autoGainControl: audioStore.autoGainControl,
                    lowCut: audioStore.lowCut,
                    midBoost: audioStore.midBoost,
                    highBoost: audioStore.highBoost,
                  },
                  overlay: {
                    lowerThird: overlayStore.lowerThird,
                    ticker: overlayStore.ticker,
                    logo: overlayStore.logo,
                    subtitles: overlayStore.subtitles,
                    ads: overlayStore.ads,
                    activeAdId: overlayStore.activeAdId,
                  },
                  prompter: {
                    text: prompterStore.text,
                    fontSize: prompterStore.fontSize,
                    speed: prompterStore.speed,
                    isPlaying: false,
                    opacity: prompterStore.opacity,
                    mirror: prompterStore.mirror,
                    width: prompterStore.width,
                    voiceScroll: prompterStore.voiceScroll,
                    voiceSensitivity: prompterStore.voiceSensitivity,
                  },
                  updatedAt: Date.now(),
                }
              : scene
          ),
        }));
      },

      captureSceneThumbnail: (id, thumbnail) =>
        set((state) => ({
          scenes: state.scenes.map((scene) =>
            scene.id === id ? { ...scene, thumbnail } : scene
          ),
        })),
    }),
    {
      name: 'kazarian-scenes',
    }
  )
);
