type ScriptType = 'vsl' | 'youtube' | 'webinar';

interface GenerateScriptParams {
  topic: string;
  type: ScriptType;
  audience?: string;
}

interface GenerateScriptResponse {
  script: string;
}

interface PolishScriptResponse {
  polished: string;
}

interface APIError {
  error: string;
  details?: string;
}

const API_BASE = '/.netlify/functions';

class OpenAIClient {
  private async fetch<T>(
    endpoint: string,
    body: Record<string, unknown>
  ): Promise<T> {
    const response = await fetch(`${API_BASE}/${endpoint}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(body),
    });

    // Check for empty response
    const text = await response.text();
    if (!text) {
      throw new Error('Пустой ответ от сервера. Убедитесь, что вы запустили приложение через "netlify dev"');
    }

    let data;
    try {
      data = JSON.parse(text);
    } catch {
      throw new Error(`Ошибка парсинга ответа: ${text.slice(0, 100)}`);
    }

    if (!response.ok) {
      const error = data as APIError;
      throw new Error(error.error || error.details || 'API request failed');
    }

    return data as T;
  }

  async generateScript(params: GenerateScriptParams): Promise<string> {
    try {
      const response = await this.fetch<GenerateScriptResponse>(
        'openai-generate',
        {
          topic: params.topic,
          type: params.type,
          audience: params.audience || '',
        }
      );
      return response.script;
    } catch (error) {
      console.error('Generate script error:', error);
      throw error;
    }
  }

  async polishScript(text: string): Promise<string> {
    try {
      const response = await this.fetch<PolishScriptResponse>('openai-polish', {
        text,
      });
      return response.polished;
    } catch (error) {
      console.error('Polish script error:', error);
      throw error;
    }
  }
}

export const openaiClient = new OpenAIClient();

// Export convenience functions
export const generateScript = (params: GenerateScriptParams) =>
  openaiClient.generateScript(params);

export const polishScript = (text: string) => openaiClient.polishScript(text);
