import { useRef, useEffect, useImperativeHandle, forwardRef, useCallback, useMemo } from 'react';
import { useVideoStore, useOverlayStore, usePrompterStore } from '@/stores';
import { getCanvasDimensions } from '@/utils';

interface VideoCanvasProps {
  isRecording: boolean;
}

export const VideoCanvas = forwardRef<HTMLCanvasElement, VideoCanvasProps>(
  ({ isRecording }, ref) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const requestRef = useRef<number>(0);
    const isMountedRef = useRef(true);

    // Store values
    const videoSettings = useVideoStore();
    const overlaySettings = useOverlayStore();
    const isMirrored = usePrompterStore((s) => s.mirror);
    const aspectRatio = useVideoStore((s) => s.aspectRatio);

    // Canvas dimensions based on aspect ratio
    const canvasDimensions = useMemo(() => getCanvasDimensions(aspectRatio), [aspectRatio]);

    // Expose canvas ref
    useImperativeHandle(ref, () => canvasRef.current!, []);

    // Initialize camera
    useEffect(() => {
      let stream: MediaStream | null = null;
      isMountedRef.current = true;

      const startCamera = async () => {
        try {
          const constraints: MediaStreamConstraints = {
            video: {
              width: { ideal: 1920 },
              height: { ideal: 1080 },
              deviceId: videoSettings.selectedDeviceId
                ? { exact: videoSettings.selectedDeviceId }
                : undefined,
            },
            audio: false,
          };

          stream = await navigator.mediaDevices.getUserMedia(constraints);

          if (!isMountedRef.current) {
            stream.getTracks().forEach((t) => t.stop());
            return;
          }

          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.onloadedmetadata = () => {
              videoRef.current?.play().catch(console.error);
            };
          }
        } catch (err) {
          console.error('Camera access error:', err);
        }
      };

      startCamera();

      return () => {
        isMountedRef.current = false;
        if (stream) {
          stream.getTracks().forEach((track) => track.stop());
        }
      };
    }, [videoSettings.selectedDeviceId]);

    // Render function
    const render = useCallback(() => {
      const canvas = canvasRef.current;
      const video = videoRef.current;

      if (!canvas || !video || video.readyState < 2) return;

      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) return;

      // Clear canvas first
      ctx.fillStyle = '#000';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Check if video has valid dimensions
      if (!video.videoWidth || !video.videoHeight) {
        // Fallback: draw video stretched to canvas
        ctx.filter = `brightness(${videoSettings.brightness}%) contrast(${videoSettings.contrast}%) saturate(${videoSettings.saturation}%) blur(${videoSettings.blur}px)`;
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        ctx.filter = 'none';
      } else {
        // Calculate video dimensions to cover canvas while maintaining aspect ratio
        const videoAspect = video.videoWidth / video.videoHeight;
        const canvasAspect = canvas.width / canvas.height;

        let drawWidth, drawHeight, drawX, drawY;

        if (videoAspect > canvasAspect) {
          // Video is wider - crop sides
          drawHeight = canvas.height;
          drawWidth = canvas.height * videoAspect;
          drawX = (canvas.width - drawWidth) / 2;
          drawY = 0;
        } else {
          // Video is taller - crop top/bottom
          drawWidth = canvas.width;
          drawHeight = canvas.width / videoAspect;
          drawX = 0;
          drawY = (canvas.height - drawHeight) / 2;
        }

        // Apply video filters
        ctx.filter = `brightness(${videoSettings.brightness}%) contrast(${videoSettings.contrast}%) saturate(${videoSettings.saturation}%) blur(${videoSettings.blur}px)`;
        ctx.drawImage(video, drawX, drawY, drawWidth, drawHeight);
        ctx.filter = 'none';
      }

      // Face light effect
      if (videoSettings.faceLight > 0) {
        const gradient = ctx.createRadialGradient(
          canvas.width / 2,
          canvas.height / 2,
          100,
          canvas.width / 2,
          canvas.height / 2,
          400
        );
        gradient.addColorStop(0, `rgba(255, 255, 255, ${videoSettings.faceLight / 200})`);
        gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');
        ctx.fillStyle = gradient;
        ctx.globalCompositeOperation = 'screen';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.globalCompositeOperation = 'source-over';
      }

      // Vignette
      if (videoSettings.vignette > 0) {
        const vGradient = ctx.createRadialGradient(
          canvas.width / 2,
          canvas.height / 2,
          canvas.height / 3,
          canvas.width / 2,
          canvas.height / 2,
          canvas.height * 0.8
        );
        vGradient.addColorStop(0, 'rgba(0,0,0,0)');
        vGradient.addColorStop(1, `rgba(0,0,0, ${videoSettings.vignette / 100})`);
        ctx.fillStyle = vGradient;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }

      // Logo overlay
      if (overlaySettings.logo.visible && overlaySettings.logo.text) {
        ctx.fillStyle = `rgba(255, 255, 255, ${overlaySettings.logo.opacity})`;
        ctx.font = 'bold 24px Inter';
        const logoText = overlaySettings.logo.text;
        const textMetrics = ctx.measureText(logoText);

        let x = 20;
        let y = 40;

        if (overlaySettings.logo.position.includes('right')) {
          x = canvas.width - textMetrics.width - 20;
        }
        if (overlaySettings.logo.position.includes('bottom')) {
          y = canvas.height - 20;
        }

        ctx.fillText(logoText, x, y);
      }

      // Lower third
      if (overlaySettings.lowerThird.visible) {
        const ltY = canvas.height - 150;
        const ltX = 50;

        if (overlaySettings.lowerThird.style === 'modern') {
          // Modern style - blue accent bar
          ctx.fillStyle = overlaySettings.lowerThird.accentColor;
          ctx.fillRect(ltX, ltY, 10, 60);

          ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';
          ctx.fillRect(ltX + 15, ltY, 400, 35);
          ctx.fillRect(ltX + 15, ltY + 35, 300, 25);

          ctx.fillStyle = overlaySettings.lowerThird.textColor;
          ctx.font = 'bold 20px Inter';
          ctx.fillText(overlaySettings.lowerThird.text1, ltX + 25, ltY + 24);

          ctx.fillStyle = '#94a3b8';
          ctx.font = '16px Inter';
          ctx.fillText(overlaySettings.lowerThird.text2, ltX + 25, ltY + 52);

        } else if (overlaySettings.lowerThird.style === 'neon') {
          // Neon style - glowing pink
          ctx.shadowColor = '#d946ef';
          ctx.shadowBlur = 20;
          ctx.fillStyle = 'rgba(0,0,0,0.8)';
          ctx.fillRect(ltX, ltY + 10, 450, 50);
          ctx.shadowBlur = 0;

          ctx.fillStyle = '#d946ef';
          ctx.font = 'bold 24px Inter';
          ctx.fillText(
            `${overlaySettings.lowerThird.text1} | ${overlaySettings.lowerThird.text2}`,
            ltX + 20,
            ltY + 42
          );

        } else if (overlaySettings.lowerThird.style === 'glass') {
          // Glass style - frosted transparent
          ctx.fillStyle = 'rgba(255, 255, 255, 0.15)';
          ctx.beginPath();
          ctx.roundRect(ltX, ltY, 420, 70, 12);
          ctx.fill();

          // Border
          ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
          ctx.lineWidth = 1;
          ctx.beginPath();
          ctx.roundRect(ltX, ltY, 420, 70, 12);
          ctx.stroke();

          ctx.fillStyle = '#ffffff';
          ctx.font = 'bold 22px Inter';
          ctx.fillText(overlaySettings.lowerThird.text1, ltX + 20, ltY + 30);

          ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
          ctx.font = '16px Inter';
          ctx.fillText(overlaySettings.lowerThird.text2, ltX + 20, ltY + 55);

        } else if (overlaySettings.lowerThird.style === 'minimal') {
          // Minimal style - just text with subtle shadow
          ctx.shadowColor = 'rgba(0, 0, 0, 0.8)';
          ctx.shadowBlur = 10;
          ctx.shadowOffsetX = 2;
          ctx.shadowOffsetY = 2;

          ctx.fillStyle = '#ffffff';
          ctx.font = 'bold 26px Inter';
          ctx.fillText(overlaySettings.lowerThird.text1, ltX, ltY + 25);

          ctx.font = '18px Inter';
          ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
          ctx.fillText(overlaySettings.lowerThird.text2, ltX, ltY + 55);

          // Reset shadow
          ctx.shadowColor = 'transparent';
          ctx.shadowBlur = 0;
          ctx.shadowOffsetX = 0;
          ctx.shadowOffsetY = 0;
        }
      }

      // Ticker
      if (overlaySettings.ticker.visible) {
        const time = Date.now() * 0.002 * overlaySettings.ticker.speed;
        const tickerY = canvas.height - 30;

        ctx.fillStyle = overlaySettings.ticker.backgroundColor;
        ctx.fillRect(0, tickerY - 20, canvas.width, 50);

        ctx.fillStyle = overlaySettings.ticker.textColor;
        ctx.font = `${overlaySettings.ticker.fontSize}px Inter`;
        const textWidth = ctx.measureText(overlaySettings.ticker.text).width;
        const pos = canvas.width - ((time * 50) % (textWidth + canvas.width));

        ctx.fillText(overlaySettings.ticker.text, pos, tickerY + 10);
      }

      // Subtitles
      if (overlaySettings.subtitles.enabled && overlaySettings.subtitles.currentText) {
        const subtitleText = overlaySettings.subtitles.currentText;
        const fontSize = overlaySettings.subtitles.fontSize;
        const maxWidth = (canvas.width * overlaySettings.subtitles.maxWidth) / 100;

        ctx.font = `bold ${fontSize}px Inter`;

        // Word wrap the text
        const words = subtitleText.split(' ');
        const lines: string[] = [];
        let currentLine = '';

        for (const word of words) {
          const testLine = currentLine ? `${currentLine} ${word}` : word;
          const metrics = ctx.measureText(testLine);
          if (metrics.width > maxWidth && currentLine) {
            lines.push(currentLine);
            currentLine = word;
          } else {
            currentLine = testLine;
          }
        }
        if (currentLine) {
          lines.push(currentLine);
        }

        // Calculate Y position
        const lineHeight = fontSize * 1.3;
        const totalHeight = lines.length * lineHeight;
        let startY: number;

        if (overlaySettings.subtitles.position === 'top') {
          startY = 60;
        } else if (overlaySettings.subtitles.position === 'center') {
          startY = (canvas.height - totalHeight) / 2;
        } else {
          startY = canvas.height - totalHeight - 80;
        }

        // Draw background and text for each line
        const padding = 12;
        ctx.textAlign = 'center';

        for (let i = 0; i < lines.length; i++) {
          const line = lines[i];
          const lineWidth = ctx.measureText(line).width;
          const y = startY + i * lineHeight;

          // Background
          ctx.fillStyle = overlaySettings.subtitles.backgroundColor;
          ctx.beginPath();
          ctx.roundRect(
            (canvas.width - lineWidth) / 2 - padding,
            y - fontSize + 4,
            lineWidth + padding * 2,
            fontSize + padding,
            6
          );
          ctx.fill();

          // Text
          ctx.fillStyle = overlaySettings.subtitles.textColor;
          ctx.fillText(line, canvas.width / 2, y);
        }

        ctx.textAlign = 'left';
      }
    }, [videoSettings, overlaySettings]);

    // Animation loop
    useEffect(() => {
      isMountedRef.current = true;

      const animate = () => {
        if (!isMountedRef.current) return;
        render();
        requestRef.current = requestAnimationFrame(animate);
      };

      animate();

      return () => {
        isMountedRef.current = false;
        cancelAnimationFrame(requestRef.current);
      };
    }, [render]);

    // Calculate aspect ratio class
    const aspectClass = aspectRatio === '9:16' ? 'aspect-[9/16]' :
                        aspectRatio === '4:3' ? 'aspect-[4/3]' :
                        aspectRatio === '1:1' ? 'aspect-square' : 'aspect-video';

    return (
      <div className={`relative bg-black rounded-lg overflow-hidden border border-slate-700 shadow-2xl ${aspectClass} max-h-[70vh] mx-auto`}>
        <video
          ref={videoRef}
          className="absolute inset-0 w-full h-full object-cover opacity-0 pointer-events-none"
          muted
          playsInline
          autoPlay
        />
        <canvas
          ref={canvasRef}
          width={canvasDimensions.width}
          height={canvasDimensions.height}
          className={`w-full h-full object-contain ${isMirrored ? 'scale-x-[-1]' : ''}`}
        />
        {isRecording && (
          <div className="absolute top-4 left-4 flex items-center gap-2 bg-red-600/90 px-3 py-1.5 rounded-full">
            <div className="w-2 h-2 bg-white rounded-full animate-pulse" />
            <span className="text-xs font-bold text-white">REC</span>
          </div>
        )}
      </div>
    );
  }
);

VideoCanvas.displayName = 'VideoCanvas';
