import React, { useState } from 'react';
import { FileText, Wand2, Loader2 } from 'lucide-react';
import { Button } from '@/components/common';
import { usePrompterStore } from '@/stores';
import { generateScript, polishScript } from '@/services/api/openaiClient';

export const ScriptEditor: React.FC = () => {
  const { text, setText } = usePrompterStore();

  const [topic, setTopic] = useState('');
  const [audience, setAudience] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (type: 'vsl' | 'youtube' | 'webinar') => {
    if (!topic.trim()) {
      setError('Введите тему');
      return;
    }

    setIsGenerating(true);
    setError(null);

    try {
      const script = await generateScript({
        topic,
        type,
        audience: audience || undefined,
      });
      setText(script);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Ошибка генерации');
    } finally {
      setIsGenerating(false);
    }
  };

  const handlePolish = async () => {
    if (!text.trim()) {
      setError('Нет текста для улучшения');
      return;
    }

    setIsGenerating(true);
    setError(null);

    try {
      const polished = await polishScript(text);
      setText(polished);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Ошибка улучшения');
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="flex flex-col h-full">
      {/* Header */}
      <div className="p-4 border-b border-slate-700 flex justify-between items-center">
        <h2 className="font-semibold flex items-center gap-2">
          <FileText size={18} />
          Редактор сценария
        </h2>
        <button
          onClick={handlePolish}
          disabled={isGenerating || !text.trim()}
          className="p-2 hover:bg-slate-800 rounded text-purple-400 disabled:opacity-50"
          title="Улучшить текст (AI)"
        >
          {isGenerating ? (
            <Loader2 size={16} className="animate-spin" />
          ) : (
            <Wand2 size={16} />
          )}
        </button>
      </div>

      {/* AI Controls */}
      <div className="p-4 bg-slate-800/50 space-y-3">
        <input
          placeholder="Тема (напр. Тревожность)"
          className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-sm text-white placeholder:text-slate-500 focus:border-blue-500 outline-none"
          value={topic}
          onChange={(e) => setTopic(e.target.value)}
        />
        <input
          placeholder="Аудитория (напр. Молодые мамы)"
          className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-sm text-white placeholder:text-slate-500 focus:border-blue-500 outline-none"
          value={audience}
          onChange={(e) => setAudience(e.target.value)}
        />

        <div className="flex gap-2">
          <Button
            onClick={() => handleGenerate('vsl')}
            disabled={isGenerating}
            isLoading={isGenerating}
            variant="primary"
            size="sm"
            className="flex-1 text-xs"
          >
            Создать VSL
          </Button>
          <Button
            onClick={() => handleGenerate('youtube')}
            disabled={isGenerating}
            variant="secondary"
            size="sm"
            className="flex-1 text-xs"
          >
            YouTube
          </Button>
          <Button
            onClick={() => handleGenerate('webinar')}
            disabled={isGenerating}
            variant="ghost"
            size="sm"
            className="flex-1 text-xs"
          >
            Вебинар
          </Button>
        </div>

        {error && (
          <p className="text-xs text-red-400 mt-2">{error}</p>
        )}
      </div>

      {/* Text Area */}
      <textarea
        className="flex-1 bg-studio-bg text-slate-300 p-4 outline-none resize-none font-mono text-sm leading-relaxed scrollbar-thin"
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="Введите или сгенерируйте текст для телесуфлёра..."
      />
    </div>
  );
};
