// Canvas
export const CANVAS_WIDTH = 1280;
export const CANVAS_HEIGHT = 720;
export const CANVAS_FPS = 30;

// Canvas dimensions by aspect ratio
export const CANVAS_DIMENSIONS: Record<string, { width: number; height: number }> = {
  '16:9': { width: 1280, height: 720 },
  '9:16': { width: 720, height: 1280 },
  '4:3': { width: 1280, height: 960 },
  '1:1': { width: 1080, height: 1080 },
};

export const getCanvasDimensions = (aspectRatio: string) => {
  return CANVAS_DIMENSIONS[aspectRatio] || CANVAS_DIMENSIONS['16:9'];
};

