import React from 'react';
import { Camera } from 'lucide-react';
import { Slider, Select, Toggle } from '@/components/common';
import { useVideoStore } from '@/stores';
import { VIDEO_FILTER_RANGES } from '@/utils';

export const VideoTab: React.FC = () => {
  const {
    brightness,
    contrast,
    saturation,
    blur,
    vignette,
    faceLight,
    selectedDeviceId,
    devices,
    isMirrored,
    virtualBackground,
    aspectRatio,
    updateSettings,
    setDevice,
    toggleMirror,
    updateVirtualBackground,
    setAspectRatio,
  } = useVideoStore();

  const deviceOptions = devices.map((d) => ({
    value: d.deviceId,
    label: d.label || `Камера ${d.deviceId.slice(0, 5)}...`,
  }));

  return (
    <div className="space-y-6">
      <h3 className="text-lg font-semibold text-white mb-4">Видео движок</h3>

      {/* Camera Select */}
      <Select
        label="Камера"
        icon={<Camera size={16} />}
        value={selectedDeviceId}
        options={deviceOptions}
        onChange={setDevice}
        placeholder="Выберите камеру"
      />

      {/* Aspect Ratio */}
      <Select
        label="Соотношение сторон"
        value={aspectRatio}
        options={[
          { value: '16:9', label: '16:9 (Горизонтальное)' },
          { value: '9:16', label: '9:16 (Вертикальное)' },
          { value: '4:3', label: '4:3 (Классическое)' },
          { value: '1:1', label: '1:1 (Квадрат)' },
        ]}
        onChange={(v) => setAspectRatio(v as '16:9' | '9:16' | '4:3' | '1:1')}
      />

      {/* Video Filters */}
      <Slider
        label="Яркость"
        value={brightness}
        min={VIDEO_FILTER_RANGES.brightness.min}
        max={VIDEO_FILTER_RANGES.brightness.max}
        unit="%"
        onChange={(v) => updateSettings({ brightness: v })}
      />

      <Slider
        label="Контраст"
        value={contrast}
        min={VIDEO_FILTER_RANGES.contrast.min}
        max={VIDEO_FILTER_RANGES.contrast.max}
        unit="%"
        onChange={(v) => updateSettings({ contrast: v })}
      />

      <Slider
        label="Насыщенность"
        value={saturation}
        min={VIDEO_FILTER_RANGES.saturation.min}
        max={VIDEO_FILTER_RANGES.saturation.max}
        unit="%"
        onChange={(v) => updateSettings({ saturation: v })}
      />

      <Slider
        label="Виньетка"
        value={vignette}
        min={VIDEO_FILTER_RANGES.vignette.min}
        max={VIDEO_FILTER_RANGES.vignette.max}
        onChange={(v) => updateSettings({ vignette: v })}
      />

      <Slider
        label="Подсветка лица"
        value={faceLight}
        min={VIDEO_FILTER_RANGES.faceLight.min}
        max={VIDEO_FILTER_RANGES.faceLight.max}
        onChange={(v) => updateSettings({ faceLight: v })}
      />

      <Slider
        label="Размытие фона"
        value={blur}
        min={VIDEO_FILTER_RANGES.blur.min}
        max={VIDEO_FILTER_RANGES.blur.max}
        unit="px"
        onChange={(v) => updateSettings({ blur: v })}
      />

      {/* Virtual Background */}
      <div className="pt-4 border-t border-slate-700">
        <Toggle
          label="Виртуальный фон"
          checked={virtualBackground.enabled}
          onChange={(v) => updateVirtualBackground({ enabled: v })}
        />

        {virtualBackground.enabled && (
          <div className="mt-4 space-y-3">
            <Select
              value={virtualBackground.type}
              options={[
                { value: 'blur', label: 'Размытие' },
                { value: 'color', label: 'Цвет' },
                { value: 'image', label: 'Изображение' },
              ]}
              onChange={(v) => updateVirtualBackground({ type: v as 'blur' | 'color' | 'image' })}
            />

            {virtualBackground.type === 'blur' && (
              <Slider
                label="Сила размытия"
                value={virtualBackground.blurStrength}
                min={5}
                max={30}
                onChange={(v) => updateVirtualBackground({ blurStrength: v })}
              />
            )}
          </div>
        )}
      </div>

      {/* Mirror */}
      <div className="pt-4 border-t border-slate-700">
        <Toggle
          label="Зеркальное отображение"
          checked={isMirrored}
          onChange={toggleMirror}
        />
      </div>
    </div>
  );
};
