import { useRef, useEffect, useCallback, useState } from 'react';
import { useAudioStore } from '@/stores';

interface AudioProcessorResult {
  audioDestination: MediaStreamAudioDestinationNode | null;
  audioContext: AudioContext | null;
  analyser: AnalyserNode | null;
  isInitialized: boolean;
  error: string | null;
}

export function useAudioProcessor(): AudioProcessorResult & {
  initialize: () => Promise<boolean>;
  cleanup: () => void;
} {
  // Use state for values that need to trigger re-renders when returned
  const [audioDestination, setAudioDestination] = useState<MediaStreamAudioDestinationNode | null>(null);
  const [audioContext, setAudioContext] = useState<AudioContext | null>(null);
  const [analyser, setAnalyser] = useState<AnalyserNode | null>(null);
  const [isInitialized, setIsInitialized] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Use refs for internal nodes that don't need to trigger re-renders
  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const eqLowRef = useRef<BiquadFilterNode | null>(null);
  const eqMidRef = useRef<BiquadFilterNode | null>(null);
  const eqHighRef = useRef<BiquadFilterNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const {
    selectedDeviceId,
    gain,
    noiseSuppression,
    echoCancellation,
    autoGainControl,
    lowCut,
    midBoost,
    highBoost,
    setMonitorLevel,
  } = useAudioStore();

  const cleanup = useCallback(() => {
    // Stop all tracks
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((track) => track.stop());
      streamRef.current = null;
    }

    // Disconnect source
    if (sourceRef.current) {
      try {
        sourceRef.current.disconnect();
      } catch {
        // Ignore disconnect errors
      }
      sourceRef.current = null;
    }

    // Close audio context
    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }

    // Clear refs
    gainNodeRef.current = null;
    eqLowRef.current = null;
    eqMidRef.current = null;
    eqHighRef.current = null;

    // Clear state
    setAudioDestination(null);
    setAudioContext(null);
    setAnalyser(null);
    setIsInitialized(false);
  }, []);

  const initialize = useCallback(async (): Promise<boolean> => {
    cleanup();

    try {
      // Get audio stream
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: {
          deviceId: selectedDeviceId ? { exact: selectedDeviceId } : undefined,
          echoCancellation,
          noiseSuppression,
          autoGainControl,
        },
      });

      streamRef.current = stream;

      // Create audio context with low latency for better sync
      const AudioContextClass = window.AudioContext || (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext;
      const ctx = new AudioContextClass({ latencyHint: 'interactive' });
      audioContextRef.current = ctx;

      // Resume if suspended
      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      // Create nodes
      const source = ctx.createMediaStreamSource(stream);
      sourceRef.current = source;

      const destination = ctx.createMediaStreamDestination();

      const gainNode = ctx.createGain();
      gainNode.gain.value = gain;
      gainNodeRef.current = gainNode;

      // EQ - Low shelf
      const low = ctx.createBiquadFilter();
      low.type = 'lowshelf';
      low.frequency.value = 320;
      low.gain.value = lowCut;
      eqLowRef.current = low;

      // EQ - Mid peaking
      const mid = ctx.createBiquadFilter();
      mid.type = 'peaking';
      mid.frequency.value = 1000;
      mid.Q.value = 1;
      mid.gain.value = midBoost;
      eqMidRef.current = mid;

      // EQ - High shelf
      const high = ctx.createBiquadFilter();
      high.type = 'highshelf';
      high.frequency.value = 3200;
      high.gain.value = highBoost;
      eqHighRef.current = high;

      // Analyser for visualization
      const analyserNode = ctx.createAnalyser();
      analyserNode.fftSize = 256;
      analyserNode.smoothingTimeConstant = 0.5;

      // Connect chain: source -> low -> mid -> high -> gain -> destination
      //                                                    -> analyser
      source.connect(low);
      low.connect(mid);
      mid.connect(high);
      high.connect(gainNode);
      gainNode.connect(destination);
      gainNode.connect(analyserNode);

      // Update state to trigger re-renders
      setAudioDestination(destination);
      setAudioContext(ctx);
      setAnalyser(analyserNode);
      setIsInitialized(true);
      setError(null);

      return true;
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : 'Audio initialization failed';
      setError(errorMsg);
      console.error('Audio processor init error:', errorMsg);
      return false;
    }
  }, [
    selectedDeviceId,
    echoCancellation,
    noiseSuppression,
    autoGainControl,
    gain,
    lowCut,
    midBoost,
    highBoost,
    cleanup,
  ]);

  // Update gain in real-time
  useEffect(() => {
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.value = gain;
    }
  }, [gain]);

  // Update EQ in real-time
  useEffect(() => {
    if (eqLowRef.current) eqLowRef.current.gain.value = lowCut;
    if (eqMidRef.current) eqMidRef.current.gain.value = midBoost;
    if (eqHighRef.current) eqHighRef.current.gain.value = highBoost;
  }, [lowCut, midBoost, highBoost]);

  // Monitor audio level
  useEffect(() => {
    if (!analyser) return;

    const dataArray = new Uint8Array(analyser.frequencyBinCount);
    let rafId: number;

    const updateLevel = () => {
      analyser.getByteFrequencyData(dataArray);

      let sum = 0;
      for (let i = 0; i < dataArray.length; i++) {
        sum += dataArray[i];
      }
      const average = sum / dataArray.length;
      const normalized = Math.min(100, Math.round((average / 60) * 100));

      setMonitorLevel(normalized);
      rafId = requestAnimationFrame(updateLevel);
    };

    updateLevel();

    return () => {
      cancelAnimationFrame(rafId);
    };
  }, [analyser, setMonitorLevel]);

  // Re-initialize when device changes
  useEffect(() => {
    if (selectedDeviceId && isInitialized) {
      initialize();
    }
  }, [selectedDeviceId]);

  // Cleanup on unmount
  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  return {
    audioDestination,
    audioContext,
    analyser,
    isInitialized,
    error,
    initialize,
    cleanup,
  };
}
