import React, { useState } from 'react';
import { clsx } from 'clsx';
import { Monitor, Music, Layers, ScrollText, Film, Radio } from 'lucide-react';
import { VideoTab } from './VideoTab';
import { AudioTab } from './AudioTab';
import { GraphicsTab } from './GraphicsTab';
import { PrompterTab } from './PrompterTab';
import { SceneTab } from './SceneTab';
import { StreamTab } from './StreamTab';

type TabId = 'video' | 'audio' | 'graphics' | 'prompter' | 'scenes' | 'stream';

interface Tab {
  id: TabId;
  label: string;
  icon: React.ElementType;
}

const tabs: Tab[] = [
  { id: 'video', label: 'Видео', icon: Monitor },
  { id: 'audio', label: 'Аудио', icon: Music },
  { id: 'graphics', label: 'Графика', icon: Layers },
  { id: 'prompter', label: 'Суфлер', icon: ScrollText },
  { id: 'scenes', label: 'Сцены', icon: Film },
  { id: 'stream', label: 'Стрим', icon: Radio },
];

export const ControlPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabId>('video');

  const renderTabContent = () => {
    switch (activeTab) {
      case 'video':
        return <VideoTab />;
      case 'audio':
        return <AudioTab />;
      case 'graphics':
        return <GraphicsTab />;
      case 'prompter':
        return <PrompterTab />;
      case 'scenes':
        return <SceneTab />;
      case 'stream':
        return <StreamTab />;
      default:
        return null;
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 border-l border-slate-700">
      {/* Tabs */}
      <div className="flex border-b border-slate-700 overflow-x-auto scrollbar-thin">
        {tabs.map((tab) => {
          const Icon = tab.icon;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={clsx(
                'flex items-center gap-1.5 px-3 py-3 text-xs font-medium transition-colors whitespace-nowrap',
                activeTab === tab.id
                  ? 'bg-blue-600 text-white border-b-2 border-blue-400'
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              )}
            >
              <Icon size={16} />
              <span className="hidden lg:inline">{tab.label}</span>
            </button>
          );
        })}
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 scrollbar-thin">
        {renderTabContent()}
      </div>
    </div>
  );
};
