import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { QRCodeSVG } from 'qrcode.react';
import { Video, Smartphone, Monitor, Lock, Unlock } from 'lucide-react';
import { useAuthStore } from '@/stores';

export const HomePage: React.FC = () => {
  const navigate = useNavigate();
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const { isAuthenticated, authenticate, logout } = useAuthStore();

  const currentUrl = window.location.origin;
  const mobileUrl = `${currentUrl}/mobile`;

  const handlePinSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (authenticate(pin)) {
      setError('');
    } else {
      setError('Неверный PIN код');
      setPin('');
    }
  };

  const handleKeyPress = (digit: string) => {
    if (pin.length < 4) {
      setPin(prev => prev + digit);
      setError('');
    }
  };

  const handleClear = () => {
    setPin('');
    setError('');
  };

  const handleBackspace = () => {
    setPin(prev => prev.slice(0, -1));
    setError('');
  };

  // If not authenticated, show PIN entry
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 flex items-center justify-center p-4">
        <div className="bg-slate-800/50 backdrop-blur-sm rounded-2xl p-8 w-full max-w-sm border border-slate-700">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl flex items-center justify-center mx-auto mb-4">
              <Lock className="w-8 h-8 text-white" />
            </div>
            <h1 className="text-2xl font-bold text-white mb-2">KazarianSuflerAIStudio</h1>
            <p className="text-slate-400 text-sm">Введите PIN код для входа</p>
          </div>

          <form onSubmit={handlePinSubmit}>
            {/* PIN Display */}
            <div className="flex justify-center gap-3 mb-6">
              {[0, 1, 2, 3].map((i) => (
                <div
                  key={i}
                  className={`w-12 h-14 rounded-lg border-2 flex items-center justify-center text-2xl font-bold transition-all ${
                    pin.length > i
                      ? 'bg-blue-500/20 border-blue-500 text-white'
                      : 'bg-slate-700/50 border-slate-600 text-slate-500'
                  }`}
                >
                  {pin.length > i ? '•' : ''}
                </div>
              ))}
            </div>

            {error && (
              <p className="text-red-400 text-center text-sm mb-4">{error}</p>
            )}

            {/* Number Pad */}
            <div className="grid grid-cols-3 gap-3 mb-4">
              {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((num) => (
                <button
                  key={num}
                  type="button"
                  onClick={() => handleKeyPress(String(num))}
                  className="h-14 rounded-lg bg-slate-700/50 hover:bg-slate-600/50 text-white text-xl font-medium transition-all active:scale-95"
                >
                  {num}
                </button>
              ))}
              <button
                type="button"
                onClick={handleClear}
                className="h-14 rounded-lg bg-red-500/20 hover:bg-red-500/30 text-red-400 text-sm font-medium transition-all"
              >
                Очистить
              </button>
              <button
                type="button"
                onClick={() => handleKeyPress('0')}
                className="h-14 rounded-lg bg-slate-700/50 hover:bg-slate-600/50 text-white text-xl font-medium transition-all active:scale-95"
              >
                0
              </button>
              <button
                type="button"
                onClick={handleBackspace}
                className="h-14 rounded-lg bg-slate-700/50 hover:bg-slate-600/50 text-white text-sm font-medium transition-all"
              >
                ←
              </button>
            </div>

            <button
              type="submit"
              disabled={pin.length !== 4}
              className="w-full py-3 rounded-lg bg-gradient-to-r from-blue-500 to-purple-600 text-white font-medium transition-all disabled:opacity-50 disabled:cursor-not-allowed hover:shadow-lg hover:shadow-blue-500/25"
            >
              Войти
            </button>
          </form>
        </div>
      </div>
    );
  }

  // Authenticated - show home page
  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900">
      {/* Header */}
      <header className="p-6 flex items-center justify-between border-b border-slate-700/50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-purple-600 rounded-xl flex items-center justify-center">
            <Video className="w-5 h-5 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-white">KazarianSuflerAIStudio</h1>
            <p className="text-xs text-slate-400">Профессиональный телесуфлёр</p>
          </div>
        </div>
        <button
          onClick={logout}
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-slate-700/50 hover:bg-slate-600/50 text-slate-300 transition-all"
        >
          <Unlock className="w-4 h-4" />
          <span className="text-sm">Выйти</span>
        </button>
      </header>

      {/* Main Content */}
      <main className="p-6 max-w-6xl mx-auto">
        <div className="grid md:grid-cols-2 gap-8">
          {/* Desktop Studio Card */}
          <div className="bg-slate-800/50 backdrop-blur-sm rounded-2xl p-6 border border-slate-700 hover:border-blue-500/50 transition-all group">
            <div className="flex items-start justify-between mb-6">
              <div>
                <div className="w-12 h-12 bg-blue-500/20 rounded-xl flex items-center justify-center mb-4 group-hover:bg-blue-500/30 transition-all">
                  <Monitor className="w-6 h-6 text-blue-400" />
                </div>
                <h2 className="text-xl font-bold text-white mb-2">Десктоп Студия</h2>
                <p className="text-slate-400 text-sm">
                  Полнофункциональная версия с записью, плашками, субтитрами и генерацией сценариев
                </p>
              </div>
            </div>

            <button
              onClick={() => navigate('/studio')}
              className="w-full py-3 rounded-lg bg-gradient-to-r from-blue-500 to-blue-600 text-white font-medium transition-all hover:shadow-lg hover:shadow-blue-500/25 active:scale-98"
            >
              Открыть студию
            </button>
          </div>

          {/* Mobile Remote Card */}
          <div className="bg-slate-800/50 backdrop-blur-sm rounded-2xl p-6 border border-slate-700 hover:border-purple-500/50 transition-all group">
            <div className="flex items-start justify-between mb-6">
              <div className="flex-1">
                <div className="w-12 h-12 bg-purple-500/20 rounded-xl flex items-center justify-center mb-4 group-hover:bg-purple-500/30 transition-all">
                  <Smartphone className="w-6 h-6 text-purple-400" />
                </div>
                <h2 className="text-xl font-bold text-white mb-2">Мобильный Пульт</h2>
                <p className="text-slate-400 text-sm">
                  Управляйте телесуфлёром с телефона. Сканируйте QR код для подключения.
                </p>
              </div>

              {/* QR Code */}
              <div className="bg-white p-3 rounded-xl ml-4">
                <QRCodeSVG
                  value={mobileUrl}
                  size={100}
                  level="H"
                  includeMargin={false}
                />
              </div>
            </div>

            <div className="flex gap-3">
              <button
                onClick={() => navigate('/mobile')}
                className="flex-1 py-3 rounded-lg bg-gradient-to-r from-purple-500 to-purple-600 text-white font-medium transition-all hover:shadow-lg hover:shadow-purple-500/25 active:scale-98"
              >
                Открыть пульт
              </button>
              <button
                onClick={() => navigator.clipboard.writeText(mobileUrl)}
                className="px-4 py-3 rounded-lg bg-slate-700/50 hover:bg-slate-600/50 text-slate-300 transition-all"
                title="Скопировать ссылку"
              >
                📋
              </button>
            </div>

            <p className="text-slate-500 text-xs text-center mt-4">
              {mobileUrl}
            </p>
          </div>
        </div>

        {/* Features Section */}
        <div className="mt-12">
          <h3 className="text-lg font-semibold text-white mb-6">Возможности</h3>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            {[
              { icon: '📝', title: 'AI Сценарии', desc: 'Генерация с ChatGPT' },
              { icon: '🎥', title: 'Запись', desc: 'Видео с микрофоном' },
              { icon: '📺', title: 'Плашки', desc: 'Нижняя треть, тикер' },
              { icon: '💬', title: 'Субтитры', desc: 'Живые субтитры' },
              { icon: '🎨', title: 'Сцены', desc: 'Сохранение настроек' },
              { icon: '🎬', title: 'RTMP', desc: 'Конфигурация стрима' },
              { icon: '🔊', title: 'Звуки', desc: 'Аплодисменты, смех' },
              { icon: '🎤', title: 'Голосовое', desc: 'Авто-прокрутка' },
            ].map((feature, i) => (
              <div key={i} className="bg-slate-800/30 rounded-xl p-4 text-center">
                <div className="text-2xl mb-2">{feature.icon}</div>
                <h4 className="text-white font-medium text-sm">{feature.title}</h4>
                <p className="text-slate-500 text-xs">{feature.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="p-6 text-center text-slate-500 text-sm">
        KazarianSuflerAIStudio v1.0 | 2026
      </footer>
    </div>
  );
};
