import React, { useState } from 'react';
import { clsx } from 'clsx';
import { StopCircle, Menu, X, Monitor } from 'lucide-react';
import { Button } from '@/components/common';
import { useRecordingStore } from '@/stores';
import { formatDuration } from '@/utils';

interface LayoutProps {
  leftPanel?: React.ReactNode;
  centerContent: React.ReactNode;
  rightPanel?: React.ReactNode;
  onStartRecording: () => void;
  onStopRecording: () => void;
  onOpenPresentation?: () => void;
}

export const Layout: React.FC<LayoutProps> = ({
  leftPanel,
  centerContent,
  rightPanel,
  onStartRecording,
  onStopRecording,
  onOpenPresentation,
}) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [activeMobilePanel, setActiveMobilePanel] = useState<'script' | 'controls'>('controls');

  const isRecording = useRecordingStore((s) => s.isRecording);
  const duration = useRecordingStore((s) => s.duration);

  return (
    <div className="flex flex-col h-screen bg-studio-bg text-white overflow-hidden font-sans">
      {/* Header */}
      <header className="h-14 md:h-16 border-b border-slate-700 bg-slate-900 flex items-center justify-between px-4 md:px-6 shrink-0 z-50 safe-top">
        {/* Logo */}
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-purple-600 rounded-lg flex items-center justify-center font-bold text-sm">
            K
          </div>
          <h1 className="text-lg md:text-xl font-bold tracking-tight hidden sm:block">
            Kazarian<span className="text-blue-400">Sufler</span>AIStudio
          </h1>
        </div>

        {/* Recording Controls */}
        <div className="flex items-center gap-2 md:gap-4">
          {/* Zoom/Presentation Button */}
          {onOpenPresentation && (
            <button
              onClick={onOpenPresentation}
              className="hidden sm:flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium rounded-lg transition-colors"
              title="Открыть окно для Zoom (шарьте это окно)"
            >
              <Monitor size={16} />
              <span>Zoom</span>
            </button>
          )}

          {/* Recording Status */}
          <div className="flex items-center gap-2">
            <span
              className={clsx(
                'w-3 h-3 rounded-full',
                isRecording ? 'bg-red-500 animate-pulse' : 'bg-slate-600'
              )}
            />
            <span
              className={clsx(
                'text-sm font-mono',
                isRecording ? 'text-red-400 font-bold' : 'text-slate-400'
              )}
            >
              {isRecording ? `REC ${formatDuration(duration)}` : 'ОЖИДАНИЕ'}
            </span>
          </div>

          {/* Record Button */}
          {!isRecording ? (
            <Button
              variant="recording"
              size="sm"
              onClick={onStartRecording}
              leftIcon={<div className="w-3 h-3 bg-white rounded-full" />}
              className="hidden sm:flex"
            >
              ЗАПИСЬ
            </Button>
          ) : (
            <Button
              variant="secondary"
              size="sm"
              onClick={onStopRecording}
              leftIcon={<StopCircle size={18} />}
            >
              СТОП
            </Button>
          )}

          {/* Mobile menu toggle */}
          <button
            className="md:hidden p-2 hover:bg-slate-800 rounded-lg"
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          >
            {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </header>

      {/* Main Content */}
      <div className="flex flex-1 overflow-hidden">
        {/* Desktop Layout */}
        <div className="hidden md:flex flex-1">
          {/* Left Panel - Script Editor */}
          {leftPanel && (
            <div className="w-[350px] bg-slate-900 border-r border-slate-700 flex flex-col shrink-0">
              {leftPanel}
            </div>
          )}

          {/* Center - Video Canvas */}
          <div className="flex-1 bg-black relative flex flex-col">
            {centerContent}
          </div>

          {/* Right Panel - Controls */}
          {rightPanel && (
            <div className="w-[320px] shrink-0">{rightPanel}</div>
          )}
        </div>

        {/* Mobile Layout */}
        <div className="flex md:hidden flex-1 flex-col relative">
          {/* Video takes full screen */}
          <div className="flex-1 bg-black relative">
            {centerContent}
          </div>

          {/* Mobile Bottom Sheet */}
          {isMobileMenuOpen && (
            <div className="absolute inset-0 bg-black/70 z-40" onClick={() => setIsMobileMenuOpen(false)} />
          )}

          <div
            className={clsx(
              'absolute bottom-0 left-0 right-0 bg-slate-900 border-t border-slate-700 z-50 transition-transform duration-300 safe-bottom',
              isMobileMenuOpen ? 'translate-y-0' : 'translate-y-[calc(100%-60px)]'
            )}
            style={{ height: '70vh' }}
          >
            {/* Mobile Panel Tabs */}
            <div className="flex border-b border-slate-700">
              <button
                className={clsx(
                  'flex-1 py-3 text-sm font-medium transition-colors',
                  activeMobilePanel === 'script'
                    ? 'bg-blue-600 text-white'
                    : 'text-slate-400 hover:text-white'
                )}
                onClick={() => setActiveMobilePanel('script')}
              >
                Скрипт
              </button>
              <button
                className={clsx(
                  'flex-1 py-3 text-sm font-medium transition-colors',
                  activeMobilePanel === 'controls'
                    ? 'bg-blue-600 text-white'
                    : 'text-slate-400 hover:text-white'
                )}
                onClick={() => setActiveMobilePanel('controls')}
              >
                Настройки
              </button>
            </div>

            {/* Mobile Panel Content */}
            <div className="flex-1 overflow-y-auto">
              {activeMobilePanel === 'script' ? leftPanel : rightPanel}
            </div>
          </div>

          {/* Mobile Record Button (floating) */}
          {!isMobileMenuOpen && !isRecording && (
            <button
              onClick={onStartRecording}
              className="absolute bottom-20 right-4 w-16 h-16 bg-red-600 rounded-full flex items-center justify-center shadow-lg shadow-red-900/50 z-30"
            >
              <div className="w-6 h-6 bg-white rounded-full" />
            </button>
          )}
        </div>
      </div>
    </div>
  );
};
