import React, { useState, useCallback } from 'react';
import { Mic, Volume2 } from 'lucide-react';
import { Slider, Select, Toggle } from '@/components/common';
import { useAudioStore } from '@/stores';
import { useSoundEffects } from '@/hooks';

export const AudioTab: React.FC = () => {
  const {
    gain,
    noiseSuppression,
    echoCancellation,
    lowCut,
    midBoost,
    highBoost,
    selectedDeviceId,
    devices,
    monitorLevel,
    isMuted,
    updateSettings,
    setDevice,
    toggleMute,
  } = useAudioStore();

  const [sfxVolume, setSfxVolume] = useState(0.8);
  const [playingEffect, setPlayingEffect] = useState<string | null>(null);

  // Reset state when sound ends
  const handleSoundEnded = useCallback((effectId: string) => {
    setPlayingEffect((current) => (current === effectId ? null : current));
  }, []);

  const recordingAudioContext = useAudioStore((s) => s.recordingAudioContext);
  const recordingAudioDestination = useAudioStore((s) => s.recordingAudioDestination);

  const { effects, play, stop } = useSoundEffects({
    volume: sfxVolume,
    onEnded: handleSoundEnded,
    audioContext: recordingAudioContext,
    audioDestination: recordingAudioDestination,
  });

  const deviceOptions = devices.map((d) => ({
    value: d.deviceId,
    label: d.label || `Микрофон ${d.deviceId.slice(0, 5)}...`,
  }));

  const handleToggleSound = (effectId: string) => {
    if (playingEffect === effectId) {
      // Same sound - stop it
      stop(effectId);
      setPlayingEffect(null);
    } else {
      // Different sound - stop previous, play new
      if (playingEffect) {
        stop(playingEffect);
      }
      play(effectId);
      setPlayingEffect(effectId);
    }
  };

  return (
    <div className="space-y-6">
      <h3 className="text-lg font-semibold text-white mb-4">Аудио студия</h3>

      {/* Microphone Select */}
      <Select
        label="Микрофон"
        icon={<Mic size={16} />}
        value={selectedDeviceId}
        options={deviceOptions}
        onChange={setDevice}
        placeholder="Выберите микрофон"
      />

      <p className="text-[10px] text-slate-500 -mt-2">
        * Убедитесь, что этот микрофон активен.
      </p>

      {/* Level Meter */}
      <div className="p-4 bg-slate-800 rounded-lg">
        <div className="h-24 flex items-end justify-between gap-1">
          {[...Array(20)].map((_, i) => {
            const barHeight = Math.min(100, Math.max(5, monitorLevel - i * 3 + Math.random() * 10));
            return (
              <div
                key={i}
                className="w-full rounded-t transition-all duration-75"
                style={{
                  height: `${barHeight}%`,
                  backgroundColor: barHeight > 80 ? '#ef4444' : barHeight > 60 ? '#eab308' : '#22c55e',
                  opacity: 0.8,
                }}
              />
            );
          })}
        </div>
        <p className="text-xs text-center mt-2 text-slate-400">Монитор входа</p>
      </div>

      {/* Mute */}
      <Toggle
        label="Отключить звук"
        checked={isMuted}
        onChange={toggleMute}
      />

      {/* Gain */}
      <Slider
        label="Усиление"
        value={gain}
        min={0}
        max={2}
        step={0.1}
        onChange={(v) => updateSettings({ gain: v })}
      />

      {/* EQ */}
      <div className="grid grid-cols-3 gap-2">
        <Slider
          label="Низ"
          value={lowCut}
          min={-10}
          max={10}
          onChange={(v) => updateSettings({ lowCut: v })}
        />
        <Slider
          label="Сред"
          value={midBoost}
          min={-10}
          max={10}
          onChange={(v) => updateSettings({ midBoost: v })}
        />
        <Slider
          label="Выс"
          value={highBoost}
          min={-10}
          max={10}
          onChange={(v) => updateSettings({ highBoost: v })}
        />
      </div>

      {/* Processing */}
      <div className="pt-4 border-t border-slate-700 space-y-3">
        <h4 className="text-sm font-medium text-slate-400 uppercase">Обработка</h4>
        <Toggle
          label="Шумоподавление"
          checked={noiseSuppression}
          onChange={(v) => updateSettings({ noiseSuppression: v })}
        />
        <Toggle
          label="Эхоподавление"
          checked={echoCancellation}
          onChange={(v) => updateSettings({ echoCancellation: v })}
        />
      </div>

      {/* Sound Effects */}
      <div className="pt-4 border-t border-slate-700">
        <div className="flex items-center justify-between mb-3">
          <h4 className="text-sm font-medium text-slate-400 uppercase">
            Звуковые эффекты
          </h4>
          <div className="flex items-center gap-2">
            <Volume2 size={14} className="text-slate-500" />
            <input
              type="range"
              min={0}
              max={1}
              step={0.1}
              value={sfxVolume}
              onChange={(e) => setSfxVolume(parseFloat(e.target.value))}
              className="w-16 h-1 bg-slate-700 rounded-full appearance-none cursor-pointer"
            />
          </div>
        </div>

        <div className="grid grid-cols-3 gap-2">
          {effects.map((effect) => {
            const isPlaying = playingEffect === effect.id;
            return (
              <button
                key={effect.id}
                onClick={() => handleToggleSound(effect.id)}
                className={`
                  flex flex-col items-center justify-center gap-1 py-2 px-1 rounded-lg text-xs font-medium
                  border transition-all duration-150 relative
                  ${
                    isPlaying
                      ? 'bg-red-600 border-red-500 animate-pulse'
                      : 'bg-slate-800 border-slate-600 hover:bg-slate-700 hover:border-slate-500 active:scale-95'
                  }
                `}
              >
                {isPlaying ? (
                  <>
                    <span className="text-lg">⏹️</span>
                    <span className="truncate w-full text-center">Стоп</span>
                  </>
                ) : (
                  <>
                    <span className="text-lg">{effect.icon}</span>
                    <span className="truncate w-full text-center">{effect.name}</span>
                  </>
                )}
              </button>
            );
          })}
        </div>

        <p className="text-[10px] text-slate-500 mt-2 text-center">
          Нажмите для воспроизведения, повторно — для остановки
        </p>
      </div>
    </div>
  );
};
