export type StreamPlatform = 'custom' | 'youtube' | 'twitch' | 'facebook' | 'vk';
export type StreamResolution = '720p' | '1080p' | '1440p' | '4k';

export interface RTMPConfig {
  id: string;
  name: string;
  platform: StreamPlatform;
  url: string;
  streamKey: string;
  bitrate: number;
  resolution: StreamResolution;
  isDefault: boolean;
}

export interface StreamState {
  configs: RTMPConfig[];
  activeConfigId: string | null;
  isStreaming: boolean;
  streamStartedAt: number | null;
  viewerCount: number;
}

export const PLATFORM_RTMP_URLS: Record<StreamPlatform, string> = {
  custom: '',
  youtube: 'rtmp://a.rtmp.youtube.com/live2',
  twitch: 'rtmp://live.twitch.tv/app',
  facebook: 'rtmps://live-api-s.facebook.com:443/rtmp',
  vk: 'rtmp://ovsu.mycdn.me/input',
};

export const RESOLUTION_DIMENSIONS: Record<StreamResolution, { width: number; height: number }> = {
  '720p': { width: 1280, height: 720 },
  '1080p': { width: 1920, height: 1080 },
  '1440p': { width: 2560, height: 1440 },
  '4k': { width: 3840, height: 2160 },
};

export const DEFAULT_RTMP_CONFIG: Omit<RTMPConfig, 'id'> = {
  name: 'Мой стрим',
  platform: 'youtube',
  url: PLATFORM_RTMP_URLS.youtube,
  streamKey: '',
  bitrate: 4500,
  resolution: '1080p',
  isDefault: true,
};

export const createStreamConfigId = (): string => {
  return `stream_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
};
