import { useRef, useEffect, useCallback } from 'react';
import { Layout } from './Layout';
import { ErrorBoundary } from '@/components/common';
import { VideoCanvas } from '@/components/studio/VideoCanvas/VideoCanvas';
import { Teleprompter } from '@/components/studio/Teleprompter/Teleprompter';
import { ScriptEditor } from '@/components/script/ScriptEditor';
import { ControlPanel } from '@/components/controls/ControlPanel';
import { useMediaDevices, useAudioProcessor, useRecorder, useLowerThirdAutoShow, useTickerAutoShow, useRecordingPrompterSync, useSubtitles, usePresentationMode, useBroadcastReceiver, useSoundEffects } from '@/hooks';
import { useRecordingStore, useAudioStore, usePrompterStore, useOverlayStore } from '@/stores';

export default function App() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Initialize media devices
  const { isLoading: devicesLoading, error: devicesError } = useMediaDevices();

  // Auto-show lower third and ticker during recording
  useLowerThirdAutoShow();
  useTickerAutoShow();

  // Sync teleprompter with recording state
  useRecordingPrompterSync();

  // Live subtitles (speech-to-text)
  useSubtitles();

  // Get prompter actions for remote control
  const prompterTogglePlay = usePrompterStore((s) => s.togglePlay);
  const prompterSetSpeed = usePrompterStore((s) => s.setSpeed);
  const prompterResetPosition = usePrompterStore((s) => s.resetPosition);
  const prompterScrollUp = usePrompterStore((s) => s.scrollUp);
  const prompterScrollDown = usePrompterStore((s) => s.scrollDown);

  // Get overlay actions for remote control
  const toggleLowerThird = useOverlayStore((s) => s.toggleLowerThird);
  const toggleTicker = useOverlayStore((s) => s.toggleTicker);

  // Presentation mode for Zoom
  const { openPresentationWindow } = usePresentationMode({ canvasRef });

  // Initialize audio processor
  const { audioDestination, audioContext, initialize: initAudio, isInitialized: audioReady } = useAudioProcessor();

  // Store audio context for sound effects routing
  const setRecordingAudio = useAudioStore((s) => s.setRecordingAudio);
  const recordingAudioContext = useAudioStore((s) => s.recordingAudioContext);
  const recordingAudioDestination = useAudioStore((s) => s.recordingAudioDestination);

  // Sound effects for remote control
  const { play: playSoundEffect } = useSoundEffects({
    audioContext: recordingAudioContext,
    audioDestination: recordingAudioDestination,
  });

  // Recording
  const { start, stop, download } = useRecorder({
    canvasRef,
    audioDestination,
  });

  const isRecording = useRecordingStore((s) => s.isRecording);

  // Initialize audio on mount
  useEffect(() => {
    if (!devicesLoading && !devicesError) {
      initAudio();
    }
  }, [devicesLoading, devicesError, initAudio]);

  // Store audio context/destination for sound effects recording
  useEffect(() => {
    if (audioContext && audioDestination) {
      setRecordingAudio(audioContext, audioDestination);
    }
  }, [audioContext, audioDestination, setRecordingAudio]);

  // Handle recording
  const handleStartRecording = useCallback(() => {
    if (!audioReady) {
      initAudio().then((success) => {
        if (success) {
          start();
        }
      });
    } else {
      start();
    }
  }, [audioReady, initAudio, start]);

  const handleStopRecording = useCallback(() => {
    stop();
    // Auto-download after short delay to ensure all data is collected
    setTimeout(() => {
      download();
    }, 100);
  }, [stop, download]);

  // Toggle recording for remote control
  const handleToggleRecording = useCallback(() => {
    if (isRecording) {
      handleStopRecording();
    } else {
      handleStartRecording();
    }
  }, [isRecording, handleStartRecording, handleStopRecording]);

  // Listen for commands from mobile remote
  useBroadcastReceiver({
    onTogglePlay: prompterTogglePlay,
    onSetSpeed: prompterSetSpeed,
    onReset: prompterResetPosition,
    onScrollUp: prompterScrollUp,
    onScrollDown: prompterScrollDown,
    onToggleRecording: handleToggleRecording,
    onPlaySound: playSoundEffect,
    onToggleLowerThird: toggleLowerThird,
    onToggleTicker: toggleTicker,
  });

  return (
    <ErrorBoundary>
      <Layout
        leftPanel={<ScriptEditor />}
        centerContent={
          <div className="flex-1 flex items-center justify-center p-4 md:p-8 overflow-hidden relative">
            <ErrorBoundary>
              <VideoCanvas ref={canvasRef} isRecording={isRecording} />
            </ErrorBoundary>

            <ErrorBoundary>
              <Teleprompter />
            </ErrorBoundary>
          </div>
        }
        rightPanel={<ControlPanel />}
        onStartRecording={handleStartRecording}
        onStopRecording={handleStopRecording}
        onOpenPresentation={openPresentationWindow}
      />
    </ErrorBoundary>
  );
}
