import { useState, useRef, useEffect, useCallback } from 'react';

interface UseVoiceActivityOptions {
  deviceId: string;
  threshold: number;
  onVoiceStart?: () => void;
  onVoiceEnd?: () => void;
  onVolumeChange?: (volume: number) => void;
}

interface UseVoiceActivityResult {
  isActive: boolean;
  isTalking: boolean;
  volume: number;
  error: string | null;
  start: () => Promise<boolean>;
  stop: () => void;
}

export function useVoiceActivity({
  deviceId,
  threshold,
  onVoiceStart,
  onVoiceEnd,
  onVolumeChange,
}: UseVoiceActivityOptions): UseVoiceActivityResult {
  const [isActive, setIsActive] = useState(false);
  const [isTalking, setIsTalking] = useState(false);
  const [volume, setVolume] = useState(0);
  const [error, setError] = useState<string | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const rafIdRef = useRef<number>(0);
  const wasTalkingRef = useRef(false);

  const cleanup = useCallback(() => {
    if (rafIdRef.current) {
      cancelAnimationFrame(rafIdRef.current);
      rafIdRef.current = 0;
    }

    if (streamRef.current) {
      streamRef.current.getTracks().forEach((track) => track.stop());
      streamRef.current = null;
    }

    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }

    analyserRef.current = null;
    setIsActive(false);
    setIsTalking(false);
    setVolume(0);
  }, []);

  const start = useCallback(async (): Promise<boolean> => {
    cleanup();

    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: {
          deviceId: deviceId ? { exact: deviceId } : undefined,
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
        },
      });

      streamRef.current = stream;

      const AudioContextClass = window.AudioContext || (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext;
      const ctx = new AudioContextClass();
      audioContextRef.current = ctx;

      if (ctx.state === 'suspended') {
        await ctx.resume();
      }

      const analyser = ctx.createAnalyser();
      analyser.fftSize = 512; // More frequency resolution
      analyser.smoothingTimeConstant = 0.3; // Faster response
      analyserRef.current = analyser;

      const source = ctx.createMediaStreamSource(stream);
      source.connect(analyser);

      const dataArray = new Uint8Array(analyser.frequencyBinCount);

      // Calculate frequency bins for speech range (300Hz - 3400Hz)
      const sampleRate = ctx.sampleRate;
      const binSize = sampleRate / analyser.fftSize;
      const speechStartBin = Math.floor(300 / binSize);
      const speechEndBin = Math.ceil(3400 / binSize);

      const analyze = () => {
        if (!analyserRef.current) return;

        analyserRef.current.getByteFrequencyData(dataArray);

        // Focus on speech frequency range (300Hz - 3400Hz) for better voice detection
        let sum = 0;
        let count = 0;
        for (let i = speechStartBin; i < speechEndBin && i < dataArray.length; i++) {
          sum += dataArray[i];
          count++;
        }
        const average = count > 0 ? sum / count : 0;
        // More sensitive normalization (divisor 40 instead of 60)
        const normalizedVol = Math.min(100, Math.round((average / 40) * 100));

        setVolume(normalizedVol);
        onVolumeChange?.(normalizedVol);

        // Check if talking
        const nowTalking = normalizedVol > threshold;
        setIsTalking(nowTalking);

        // Trigger callbacks on state change
        if (nowTalking && !wasTalkingRef.current) {
          onVoiceStart?.();
        } else if (!nowTalking && wasTalkingRef.current) {
          onVoiceEnd?.();
        }
        wasTalkingRef.current = nowTalking;

        rafIdRef.current = requestAnimationFrame(analyze);
      };

      analyze();
      setIsActive(true);
      setError(null);

      return true;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Voice activity detection failed';
      setError(errorMessage);
      console.error('VAD error:', errorMessage);
      return false;
    }
  }, [deviceId, threshold, onVoiceStart, onVoiceEnd, onVolumeChange, cleanup]);

  const stop = useCallback(() => {
    cleanup();
  }, [cleanup]);

  // Cleanup on unmount
  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  // Restart when device or threshold changes
  useEffect(() => {
    if (isActive) {
      start();
    }
  }, [deviceId, threshold]); // Intentionally not including start to avoid loops

  return {
    isActive,
    isTalking,
    volume,
    error,
    start,
    stop,
  };
}
