import React from 'react';
import { Slider, Toggle } from '@/components/common';
import { usePrompterStore } from '@/stores';
import { PROMPTER_CONFIG } from '@/utils';

export const PrompterTab: React.FC = () => {
  const {
    fontSize,
    width,
    opacity,
    speed,
    mirror,
    voiceScroll,
    voiceSensitivity,
    estimatedReadTime,
    updateSettings,
    toggleMirror,
    toggleVoiceScroll,
  } = usePrompterStore();

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="space-y-6">
      <h3 className="text-lg font-semibold text-white mb-4">Настройки суфлера</h3>

      {/* Estimated Read Time */}
      <div className="bg-slate-800 p-3 rounded-lg text-center">
        <p className="text-xs text-slate-400 uppercase mb-1">Время чтения</p>
        <p className="text-2xl font-mono text-white">{formatTime(estimatedReadTime)}</p>
      </div>

      {/* Font Size */}
      <Slider
        label="Размер шрифта"
        value={fontSize}
        min={PROMPTER_CONFIG.MIN_FONT_SIZE}
        max={PROMPTER_CONFIG.MAX_FONT_SIZE}
        unit="px"
        onChange={(v) => updateSettings({ fontSize: v })}
      />

      {/* Width */}
      <Slider
        label="Ширина текста"
        value={width}
        min={PROMPTER_CONFIG.MIN_WIDTH}
        max={PROMPTER_CONFIG.MAX_WIDTH}
        unit="%"
        onChange={(v) => updateSettings({ width: v })}
      />

      {/* Opacity */}
      <Slider
        label="Прозрачность фона"
        value={Math.round(opacity * 100)}
        min={0}
        max={100}
        unit="%"
        onChange={(v) => updateSettings({ opacity: v / 100 })}
      />

      {/* Speed */}
      <Slider
        label="Скорость автопрокрутки"
        value={speed}
        min={PROMPTER_CONFIG.MIN_SPEED}
        max={PROMPTER_CONFIG.MAX_SPEED}
        step={0.1}
        onChange={(v) => updateSettings({ speed: v })}
      />

      {/* Mirror Mode */}
      <div className="bg-slate-800 p-4 rounded-lg space-y-3">
        <Toggle
          label="Зеркалить текст (для зеркал)"
          checked={mirror}
          onChange={toggleMirror}
        />

        {/* Voice Scroll */}
        <div className="border border-green-900/50 bg-green-900/10 rounded p-3">
          <Toggle
            label="Голосовая прокрутка (Beta)"
            checked={voiceScroll}
            onChange={toggleVoiceScroll}
          />

          {voiceScroll && (
            <div className="mt-3 pt-3 border-t border-slate-700">
              <Slider
                label="Порог голоса (Чувствительность)"
                value={voiceSensitivity}
                min={1}
                max={50}
                onChange={(v) => updateSettings({ voiceSensitivity: v })}
              />
              <p className="text-[10px] text-slate-400 -mt-2">
                Чем ниже значение, тем тише можно говорить для старта прокрутки.
              </p>
            </div>
          )}

          <p className="text-[10px] text-slate-400 mt-2">
            * Автоматическая прокрутка при обнаружении голоса.
          </p>
        </div>
      </div>

      {/* Keyboard Shortcuts */}
      <div className="bg-slate-800 p-4 rounded-lg">
        <h4 className="text-sm font-medium text-slate-400 mb-3 uppercase">
          Горячие клавиши
        </h4>
        <div className="space-y-2 text-sm">
          <div className="flex justify-between">
            <span className="text-slate-400">Старт/Пауза</span>
            <kbd className="bg-slate-700 px-2 py-1 rounded text-xs">Space</kbd>
          </div>
        </div>
      </div>
    </div>
  );
};
