import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { OverlayState, LowerThird, Ticker, Logo, Subtitles, AdOverlay } from '@/types';
import { DEFAULT_LOWER_THIRD, DEFAULT_TICKER, DEFAULT_LOGO, DEFAULT_SUBTITLES } from '@/types';

interface OverlayActions {
  updateLowerThird: (settings: Partial<LowerThird>) => void;
  updateTicker: (settings: Partial<Ticker>) => void;
  updateLogo: (settings: Partial<Logo>) => void;
  updateSubtitles: (settings: Partial<Subtitles>) => void;
  addAd: (ad: AdOverlay) => void;
  updateAd: (id: string, settings: Partial<AdOverlay>) => void;
  removeAd: (id: string) => void;
  setActiveAd: (id: string | null) => void;
  toggleLowerThird: () => void;
  toggleTicker: () => void;
  toggleLogo: () => void;
  toggleSubtitles: () => void;
  reset: () => void;
}

const initialState: OverlayState = {
  lowerThird: DEFAULT_LOWER_THIRD,
  ticker: DEFAULT_TICKER,
  logo: DEFAULT_LOGO,
  subtitles: DEFAULT_SUBTITLES,
  ads: [],
  activeAdId: null,
};

export const useOverlayStore = create<OverlayState & OverlayActions>()(
  persist(
    (set) => ({
      ...initialState,

      updateLowerThird: (settings) =>
        set((state) => ({
          lowerThird: { ...state.lowerThird, ...settings },
        })),

      updateTicker: (settings) =>
        set((state) => ({
          ticker: { ...state.ticker, ...settings },
        })),

      updateLogo: (settings) =>
        set((state) => ({
          logo: { ...state.logo, ...settings },
        })),

      updateSubtitles: (settings) =>
        set((state) => ({
          subtitles: { ...state.subtitles, ...settings },
        })),

      addAd: (ad) =>
        set((state) => ({
          ads: [...state.ads, ad],
        })),

      updateAd: (id, settings) =>
        set((state) => ({
          ads: state.ads.map((ad) =>
            ad.id === id ? { ...ad, ...settings } : ad
          ),
        })),

      removeAd: (id) =>
        set((state) => ({
          ads: state.ads.filter((ad) => ad.id !== id),
          activeAdId: state.activeAdId === id ? null : state.activeAdId,
        })),

      setActiveAd: (id) =>
        set({ activeAdId: id }),

      toggleLowerThird: () =>
        set((state) => ({
          lowerThird: { ...state.lowerThird, visible: !state.lowerThird.visible },
        })),

      toggleTicker: () =>
        set((state) => ({
          ticker: { ...state.ticker, visible: !state.ticker.visible },
        })),

      toggleLogo: () =>
        set((state) => ({
          logo: { ...state.logo, visible: !state.logo.visible },
        })),

      toggleSubtitles: () =>
        set((state) => ({
          subtitles: { ...state.subtitles, enabled: !state.subtitles.enabled },
        })),

      reset: () =>
        set(initialState),
    }),
    {
      name: 'kazarian-overlay-settings',
    }
  )
);
