import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Play,
  Pause,
  ChevronUp,
  ChevronDown,
  RotateCcw,
  Home,
  Minus,
  Plus,
  Circle,
  Square,
  Type,
  MessageSquare
} from 'lucide-react';
import { useAuthStore } from '@/stores';
import { useBroadcastSender } from '@/hooks/useBroadcastSync';

// Sound effects available
const SOUND_BUTTONS = [
  { id: 'applause', icon: '👏', label: 'Аплодисменты' },
  { id: 'laugh', icon: '😂', label: 'Смех' },
  { id: 'drum-roll', icon: '🥁', label: 'Барабан' },
  { id: 'plashka', icon: '📢', label: 'Звук' },
];

export const MobileRemote: React.FC = () => {
  const navigate = useNavigate();
  const { isAuthenticated, authenticate, logout } = useAuthStore();
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');

  // Local state for UI feedback
  const [localIsPlaying, setLocalIsPlaying] = useState(false);
  const [localSpeed, setLocalSpeed] = useState(1.5);
  const [localIsRecording, setLocalIsRecording] = useState(false);
  const [localLowerThird, setLocalLowerThird] = useState(false);
  const [localTicker, setLocalTicker] = useState(false);

  // Broadcast sender for remote control
  const broadcast = useBroadcastSender();

  // Handlers that broadcast to studio
  const handleTogglePlay = () => {
    setLocalIsPlaying(!localIsPlaying);
    broadcast.togglePlay();
  };

  const handleSetSpeed = (newSpeed: number) => {
    setLocalSpeed(newSpeed);
    broadcast.setSpeed(newSpeed);
  };

  const handleReset = () => {
    setLocalIsPlaying(false);
    broadcast.reset();
  };

  const handleScrollUp = () => {
    broadcast.scrollUp();
  };

  const handleScrollDown = () => {
    broadcast.scrollDown();
  };

  const handleToggleRecording = () => {
    setLocalIsRecording(!localIsRecording);
    broadcast.toggleRecording();
  };

  const handlePlaySound = (soundId: string) => {
    broadcast.playSound(soundId);
  };

  const handleToggleLowerThird = () => {
    setLocalLowerThird(!localLowerThird);
    broadcast.toggleLowerThird();
  };

  const handleToggleTicker = () => {
    setLocalTicker(!localTicker);
    broadcast.toggleTicker();
  };

  // PIN protection for mobile remote too
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-slate-800 rounded-2xl p-6 w-full max-w-xs">
          <h1 className="text-xl font-bold text-white text-center mb-6">
            Мобильный пульт
          </h1>

          <div className="flex justify-center gap-2 mb-4">
            {[0, 1, 2, 3].map((i) => (
              <div
                key={i}
                className={`w-10 h-12 rounded-lg border-2 flex items-center justify-center text-xl font-bold ${
                  pin.length > i
                    ? 'bg-blue-500/20 border-blue-500 text-white'
                    : 'bg-slate-700 border-slate-600 text-slate-500'
                }`}
              >
                {pin.length > i ? '•' : ''}
              </div>
            ))}
          </div>

          {error && <p className="text-red-400 text-center text-sm mb-4">{error}</p>}

          <div className="grid grid-cols-3 gap-2 mb-4">
            {[1, 2, 3, 4, 5, 6, 7, 8, 9, '', 0, '←'].map((num, i) => (
              <button
                key={i}
                onClick={() => {
                  if (num === '←') {
                    setPin(p => p.slice(0, -1));
                  } else if (num !== '' && pin.length < 4) {
                    const newPin = pin + num;
                    setPin(newPin);
                    if (newPin.length === 4) {
                      if (!authenticate(newPin)) {
                        setError('Неверный PIN');
                        setPin('');
                      }
                    }
                  }
                }}
                disabled={num === ''}
                className={`h-12 rounded-lg text-lg font-medium transition-all active:scale-95 ${
                  num === ''
                    ? 'bg-transparent'
                    : 'bg-slate-700 hover:bg-slate-600 text-white'
                }`}
              >
                {num}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col pb-safe">
      {/* Header */}
      <header className="p-3 flex items-center justify-between border-b border-slate-700 sticky top-0 bg-slate-900 z-10">
        <h1 className="text-base font-bold text-white">Пульт управления</h1>
        <div className="flex gap-2">
          <button
            onClick={() => navigate('/')}
            className="p-2 rounded-lg bg-slate-800 text-slate-400 hover:text-white transition-all"
          >
            <Home className="w-4 h-4" />
          </button>
          <button
            onClick={logout}
            className="px-2 py-1 rounded-lg bg-slate-800 text-slate-400 text-xs hover:text-white transition-all"
          >
            Выйти
          </button>
        </div>
      </header>

      {/* Main Controls */}
      <main className="flex-1 p-3 flex flex-col gap-3 overflow-y-auto">
        {/* Recording Button - Big and prominent */}
        <button
          onClick={handleToggleRecording}
          className={`h-20 rounded-2xl flex items-center justify-center gap-3 transition-all active:scale-95 ${
            localIsRecording
              ? 'bg-red-600 text-white animate-pulse'
              : 'bg-red-500/20 text-red-400 border-2 border-red-500'
          }`}
        >
          {localIsRecording ? (
            <>
              <Square className="w-8 h-8" fill="currentColor" />
              <span className="text-xl font-bold">СТОП</span>
            </>
          ) : (
            <>
              <Circle className="w-8 h-8" fill="currentColor" />
              <span className="text-xl font-bold">ЗАПИСЬ</span>
            </>
          )}
        </button>

        {/* Play/Pause & Reset */}
        <div className="grid grid-cols-2 gap-3">
          <button
            onClick={handleTogglePlay}
            className={`h-24 rounded-2xl flex flex-col items-center justify-center gap-1 transition-all active:scale-95 ${
              localIsPlaying
                ? 'bg-amber-500 text-white'
                : 'bg-green-500 text-white'
            }`}
          >
            {localIsPlaying ? (
              <>
                <Pause className="w-10 h-10" />
                <span className="font-medium text-sm">Пауза</span>
              </>
            ) : (
              <>
                <Play className="w-10 h-10" />
                <span className="font-medium text-sm">Старт</span>
              </>
            )}
          </button>

          <button
            onClick={handleReset}
            className="h-24 rounded-2xl bg-slate-800 text-slate-300 flex flex-col items-center justify-center gap-1 transition-all active:scale-95 hover:bg-slate-700"
          >
            <RotateCcw className="w-8 h-8" />
            <span className="font-medium text-sm">Сброс</span>
          </button>
        </div>

        {/* Manual Scroll */}
        <div className="grid grid-cols-2 gap-3">
          <button
            onClick={handleScrollUp}
            className="h-16 rounded-xl bg-slate-800 text-slate-300 flex items-center justify-center gap-2 transition-all active:scale-95 hover:bg-slate-700"
          >
            <ChevronUp className="w-6 h-6" />
            <span className="text-sm">Вверх</span>
          </button>
          <button
            onClick={handleScrollDown}
            className="h-16 rounded-xl bg-slate-800 text-slate-300 flex items-center justify-center gap-2 transition-all active:scale-95 hover:bg-slate-700"
          >
            <ChevronDown className="w-6 h-6" />
            <span className="text-sm">Вниз</span>
          </button>
        </div>

        {/* Speed Control */}
        <div className="bg-slate-800 rounded-xl p-3">
          <div className="flex items-center justify-between mb-2">
            <span className="text-slate-400 text-xs">Скорость</span>
            <span className="text-white font-bold">{localSpeed.toFixed(1)}x</span>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={() => handleSetSpeed(Math.max(0.5, localSpeed - 0.5))}
              className="w-10 h-10 rounded-lg bg-slate-700 text-white flex items-center justify-center transition-all active:scale-95"
            >
              <Minus className="w-5 h-5" />
            </button>
            <input
              type="range"
              min="0.5"
              max="5"
              step="0.1"
              value={localSpeed}
              onChange={(e) => handleSetSpeed(parseFloat(e.target.value))}
              className="flex-1 h-2 bg-slate-700 rounded-full appearance-none cursor-pointer"
            />
            <button
              onClick={() => handleSetSpeed(Math.min(5, localSpeed + 0.5))}
              className="w-10 h-10 rounded-lg bg-slate-700 text-white flex items-center justify-center transition-all active:scale-95"
            >
              <Plus className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Overlays Section */}
        <div className="bg-slate-800 rounded-xl p-3">
          <p className="text-slate-400 text-xs mb-2">Плашки</p>
          <div className="grid grid-cols-2 gap-2">
            <button
              onClick={handleToggleLowerThird}
              className={`h-14 rounded-lg flex items-center justify-center gap-2 transition-all active:scale-95 ${
                localLowerThird
                  ? 'bg-blue-500 text-white'
                  : 'bg-slate-700 text-slate-300 hover:bg-slate-600'
              }`}
            >
              <Type className="w-5 h-5" />
              <span className="text-sm font-medium">Плашка</span>
            </button>
            <button
              onClick={handleToggleTicker}
              className={`h-14 rounded-lg flex items-center justify-center gap-2 transition-all active:scale-95 ${
                localTicker
                  ? 'bg-purple-500 text-white'
                  : 'bg-slate-700 text-slate-300 hover:bg-slate-600'
              }`}
            >
              <MessageSquare className="w-5 h-5" />
              <span className="text-sm font-medium">Бегущая</span>
            </button>
          </div>
        </div>

        {/* Sound Effects Section */}
        <div className="bg-slate-800 rounded-xl p-3">
          <p className="text-slate-400 text-xs mb-2">Звуковые эффекты</p>
          <div className="grid grid-cols-4 gap-2">
            {SOUND_BUTTONS.map((sound) => (
              <button
                key={sound.id}
                onClick={() => handlePlaySound(sound.id)}
                className="h-14 rounded-lg bg-slate-700 hover:bg-slate-600 flex flex-col items-center justify-center gap-1 transition-all active:scale-95"
              >
                <span className="text-xl">{sound.icon}</span>
                <span className="text-[10px] text-slate-400">{sound.label.slice(0, 6)}</span>
              </button>
            ))}
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="p-2 text-center text-slate-600 text-[10px] border-t border-slate-800">
        KazarianSuflerAIStudio
      </footer>
    </div>
  );
};
