export type RecordingFormat = 'webm' | 'mp4';
export type RecordingQuality = 'low' | 'medium' | 'high' | 'ultra';

export interface RecordingSettings {
  format: RecordingFormat;
  quality: RecordingQuality;
  includeAudio: boolean;
  audioBitrate: number;
  videoBitrate: number;
}

export interface RecordingState {
  isRecording: boolean;
  isPaused: boolean;
  duration: number;
  startedAt: number | null;
  recordedBlobs: Blob[];
  settings: RecordingSettings;
}

export const QUALITY_PRESETS: Record<RecordingQuality, { videoBitrate: number; audioBitrate: number }> = {
  low: { videoBitrate: 1000000, audioBitrate: 64000 },
  medium: { videoBitrate: 2500000, audioBitrate: 128000 },
  high: { videoBitrate: 5000000, audioBitrate: 192000 },
  ultra: { videoBitrate: 8000000, audioBitrate: 256000 },
};

export const DEFAULT_RECORDING_SETTINGS: RecordingSettings = {
  format: 'webm',
  quality: 'high',
  includeAudio: true,
  audioBitrate: QUALITY_PRESETS.high.audioBitrate,
  videoBitrate: QUALITY_PRESETS.high.videoBitrate,
};
