import { create } from 'zustand';
import type { RecordingState, RecordingSettings } from '@/types';
import { DEFAULT_RECORDING_SETTINGS, QUALITY_PRESETS } from '@/types';

interface RecordingActions {
  updateSettings: (settings: Partial<RecordingSettings>) => void;
  setQuality: (quality: RecordingSettings['quality']) => void;
  start: () => void;
  stop: () => void;
  pause: () => void;
  resume: () => void;
  addBlob: (blob: Blob) => void;
  clearBlobs: () => void;
  setDuration: (duration: number) => void;
  incrementDuration: () => void;
  reset: () => void;
}

const initialState: RecordingState = {
  isRecording: false,
  isPaused: false,
  duration: 0,
  startedAt: null,
  recordedBlobs: [],
  settings: DEFAULT_RECORDING_SETTINGS,
};

export const useRecordingStore = create<RecordingState & RecordingActions>()(
  (set) => ({
    ...initialState,

    updateSettings: (settings) =>
      set((state) => ({
        settings: { ...state.settings, ...settings },
      })),

    setQuality: (quality) =>
      set((state) => ({
        settings: {
          ...state.settings,
          quality,
          videoBitrate: QUALITY_PRESETS[quality].videoBitrate,
          audioBitrate: QUALITY_PRESETS[quality].audioBitrate,
        },
      })),

    start: () =>
      set({
        isRecording: true,
        isPaused: false,
        duration: 0,
        startedAt: Date.now(),
        recordedBlobs: [],
      }),

    stop: () =>
      set({
        isRecording: false,
        isPaused: false,
        startedAt: null,
      }),

    pause: () =>
      set({ isPaused: true }),

    resume: () =>
      set({ isPaused: false }),

    addBlob: (blob) =>
      set((state) => {
        // Use push for better performance with long recordings
        // (spread operator creates new array each time which is slow for large arrays)
        state.recordedBlobs.push(blob);
        return { recordedBlobs: state.recordedBlobs };
      }),

    clearBlobs: () =>
      set({ recordedBlobs: [] }),

    setDuration: (duration) =>
      set({ duration }),

    incrementDuration: () =>
      set((state) => ({
        duration: state.isPaused ? state.duration : state.duration + 1,
      })),

    reset: () =>
      set(initialState),
  })
);

// Selector for formatted duration
export const selectFormattedDuration = (state: RecordingState): string => {
  const mins = Math.floor(state.duration / 60)
    .toString()
    .padStart(2, '0');
  const secs = (state.duration % 60).toString().padStart(2, '0');
  return `${mins}:${secs}`;
};
