import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { StreamState, RTMPConfig } from '@/types';
import { PLATFORM_RTMP_URLS, DEFAULT_RTMP_CONFIG, createStreamConfigId } from '@/types';

interface StreamActions {
  addConfig: (config: Omit<RTMPConfig, 'id'>) => RTMPConfig;
  updateConfig: (id: string, updates: Partial<RTMPConfig>) => void;
  deleteConfig: (id: string) => void;
  setActiveConfig: (id: string | null) => void;
  setDefaultConfig: (id: string) => void;
  startStreaming: () => void;
  stopStreaming: () => void;
  setViewerCount: (count: number) => void;
  updatePlatformUrl: (id: string, platform: RTMPConfig['platform']) => void;
}

const initialState: StreamState = {
  configs: [],
  activeConfigId: null,
  isStreaming: false,
  streamStartedAt: null,
  viewerCount: 0,
};

export const useStreamStore = create<StreamState & StreamActions>()(
  persist(
    (set) => ({
      ...initialState,

      addConfig: (config) => {
        const newConfig: RTMPConfig = {
          ...config,
          id: createStreamConfigId(),
        };

        set((state) => {
          const isFirst = state.configs.length === 0;
          return {
            configs: [...state.configs, { ...newConfig, isDefault: isFirst }],
            activeConfigId: isFirst ? newConfig.id : state.activeConfigId,
          };
        });

        return newConfig;
      },

      updateConfig: (id, updates) =>
        set((state) => ({
          configs: state.configs.map((config) =>
            config.id === id ? { ...config, ...updates } : config
          ),
        })),

      deleteConfig: (id) =>
        set((state) => {
          const filtered = state.configs.filter((c) => c.id !== id);
          const wasDefault = state.configs.find((c) => c.id === id)?.isDefault;

          if (wasDefault && filtered.length > 0) {
            filtered[0].isDefault = true;
          }

          return {
            configs: filtered,
            activeConfigId:
              state.activeConfigId === id
                ? filtered.find((c) => c.isDefault)?.id || null
                : state.activeConfigId,
          };
        }),

      setActiveConfig: (id) =>
        set({ activeConfigId: id }),

      setDefaultConfig: (id) =>
        set((state) => ({
          configs: state.configs.map((config) => ({
            ...config,
            isDefault: config.id === id,
          })),
        })),

      startStreaming: () =>
        set({
          isStreaming: true,
          streamStartedAt: Date.now(),
          viewerCount: 0,
        }),

      stopStreaming: () =>
        set({
          isStreaming: false,
          streamStartedAt: null,
          viewerCount: 0,
        }),

      setViewerCount: (count) =>
        set({ viewerCount: count }),

      updatePlatformUrl: (id, platform) =>
        set((state) => ({
          configs: state.configs.map((config) =>
            config.id === id
              ? {
                  ...config,
                  platform,
                  url: PLATFORM_RTMP_URLS[platform],
                }
              : config
          ),
        })),
    }),
    {
      name: 'kazarian-stream-settings',
      partialize: (state) => ({
        configs: state.configs.map((c) => ({
          ...c,
          streamKey: '', // Don't persist stream keys
        })),
      }),
    }
  )
);

// Helper to get active config
export const selectActiveConfig = (state: StreamState): RTMPConfig | null => {
  return state.configs.find((c) => c.id === state.activeConfigId) || null;
};

// Create default config if none exists
export const ensureDefaultConfig = () => {
  const { configs, addConfig } = useStreamStore.getState();
  if (configs.length === 0) {
    addConfig(DEFAULT_RTMP_CONFIG);
  }
};
