import { useState, useEffect, useCallback } from 'react';
import { useVideoStore, useAudioStore } from '@/stores';

interface MediaDevicesState {
  videoDevices: MediaDeviceInfo[];
  audioDevices: MediaDeviceInfo[];
  isLoading: boolean;
  error: string | null;
  hasPermission: boolean;
}

export function useMediaDevices() {
  const [state, setState] = useState<MediaDevicesState>({
    videoDevices: [],
    audioDevices: [],
    isLoading: true,
    error: null,
    hasPermission: false,
  });

  const setVideoDevices = useVideoStore((s) => s.setDevices);
  const setAudioDevices = useAudioStore((s) => s.setDevices);

  const requestPermissions = useCallback(async () => {
    setState((prev) => ({ ...prev, isLoading: true, error: null }));

    try {
      // Request permissions by getting a stream
      const stream = await navigator.mediaDevices.getUserMedia({
        video: true,
        audio: true,
      });

      // Stop all tracks immediately - we just needed permissions
      stream.getTracks().forEach((track) => track.stop());

      setState((prev) => ({ ...prev, hasPermission: true }));
      return true;
    } catch (err) {
      const error = err instanceof Error ? err.message : 'Permission denied';
      setState((prev) => ({
        ...prev,
        error,
        hasPermission: false,
        isLoading: false,
      }));
      return false;
    }
  }, []);

  const enumerateDevices = useCallback(async () => {
    try {
      const devices = await navigator.mediaDevices.enumerateDevices();

      const videoDevices = devices.filter((d) => d.kind === 'videoinput');
      const audioDevices = devices.filter((d) => d.kind === 'audioinput');

      setState((prev) => ({
        ...prev,
        videoDevices,
        audioDevices,
        isLoading: false,
        error: null,
      }));

      // Update stores
      setVideoDevices(videoDevices);
      setAudioDevices(audioDevices);

      return { videoDevices, audioDevices };
    } catch (err) {
      const error = err instanceof Error ? err.message : 'Failed to enumerate devices';
      setState((prev) => ({
        ...prev,
        error,
        isLoading: false,
      }));
      return { videoDevices: [], audioDevices: [] };
    }
  }, [setVideoDevices, setAudioDevices]);

  const refresh = useCallback(async () => {
    const hasPermission = await requestPermissions();
    if (hasPermission) {
      await enumerateDevices();
    }
  }, [requestPermissions, enumerateDevices]);

  // Initial load
  useEffect(() => {
    let isMounted = true;

    const init = async () => {
      // Check if we already have permissions by trying to enumerate
      const devices = await navigator.mediaDevices.enumerateDevices();
      const hasLabels = devices.some((d) => d.label !== '');

      if (hasLabels) {
        // Already have permissions
        if (isMounted) {
          setState((prev) => ({ ...prev, hasPermission: true }));
          await enumerateDevices();
        }
      } else {
        // Need to request permissions
        const granted = await requestPermissions();
        if (granted && isMounted) {
          await enumerateDevices();
        }
      }
    };

    init();

    // Listen for device changes
    const handleDeviceChange = () => {
      if (isMounted) {
        enumerateDevices();
      }
    };

    navigator.mediaDevices.addEventListener('devicechange', handleDeviceChange);

    return () => {
      isMounted = false;
      navigator.mediaDevices.removeEventListener('devicechange', handleDeviceChange);
    };
  }, [enumerateDevices, requestPermissions]);

  return {
    ...state,
    refresh,
    requestPermissions,
  };
}
