import React, { useState } from 'react';
import { Plus, Copy, Trash2, Check } from 'lucide-react';
import { clsx } from 'clsx';
import { Button, Modal, ModalBody, ModalFooter } from '@/components/common';
import { useSceneStore } from '@/stores';
import { formatRelativeTime } from '@/utils';

export const SceneTab: React.FC = () => {
  const {
    scenes,
    activeSceneId,
    createScene,
    duplicateScene,
    deleteScene,
    loadScene,
    saveCurrentToScene,
  } = useSceneStore();

  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [newSceneName, setNewSceneName] = useState('');

  const handleCreateScene = () => {
    if (newSceneName.trim()) {
      createScene(newSceneName.trim());
      setNewSceneName('');
      setIsCreateModalOpen(false);
    }
  };

  const handleDeleteScene = (id: string) => {
    if (confirm('Удалить сцену?')) {
      deleteScene(id);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold text-white">Сцены</h3>
        <Button
          size="sm"
          onClick={() => setIsCreateModalOpen(true)}
          leftIcon={<Plus size={16} />}
        >
          Новая
        </Button>
      </div>

      {scenes.length === 0 ? (
        <div className="text-center py-8 text-slate-400">
          <p className="mb-2">Нет сохранённых сцен</p>
          <p className="text-xs">
            Создайте сцену, чтобы сохранить текущие настройки
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {scenes.map((scene) => (
            <div
              key={scene.id}
              className={clsx(
                'p-4 rounded-lg border transition-colors cursor-pointer',
                activeSceneId === scene.id
                  ? 'bg-blue-600/20 border-blue-500'
                  : 'bg-slate-800 border-slate-700 hover:border-slate-600'
              )}
              onClick={() => loadScene(scene.id)}
            >
              <div className="flex items-start justify-between mb-2">
                <div className="flex-1 min-w-0">
                  <h4 className="font-medium text-white truncate">
                    {scene.name}
                  </h4>
                  <p className="text-xs text-slate-400">
                    {formatRelativeTime(scene.updatedAt)}
                  </p>
                </div>

                <div className="flex items-center gap-1 ml-2">
                  {activeSceneId === scene.id && (
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        saveCurrentToScene(scene.id);
                      }}
                      className="p-1.5 hover:bg-slate-700 rounded text-green-400"
                      title="Сохранить текущие настройки"
                    >
                      <Check size={14} />
                    </button>
                  )}
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      duplicateScene(scene.id);
                    }}
                    className="p-1.5 hover:bg-slate-700 rounded text-slate-400"
                    title="Дублировать"
                  >
                    <Copy size={14} />
                  </button>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      handleDeleteScene(scene.id);
                    }}
                    className="p-1.5 hover:bg-slate-700 rounded text-red-400"
                    title="Удалить"
                  >
                    <Trash2 size={14} />
                  </button>
                </div>
              </div>

              {/* Scene Preview */}
              {scene.thumbnail ? (
                <div className="aspect-video bg-slate-900 rounded overflow-hidden">
                  <img
                    src={scene.thumbnail}
                    alt={scene.name}
                    className="w-full h-full object-cover"
                  />
                </div>
              ) : (
                <div className="aspect-video bg-slate-900 rounded flex items-center justify-center">
                  <span className="text-xs text-slate-500">Нет превью</span>
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Info */}
      <div className="bg-slate-800 p-3 rounded-lg">
        <p className="text-xs text-slate-400">
          Сцены сохраняют все настройки: видео, аудио, графику и текст суфлера.
          Переключайтесь между сценами мгновенно во время записи.
        </p>
      </div>

      {/* Create Modal */}
      <Modal
        isOpen={isCreateModalOpen}
        onClose={() => setIsCreateModalOpen(false)}
        title="Новая сцена"
        size="sm"
      >
        <ModalBody>
          <input
            type="text"
            placeholder="Название сцены"
            value={newSceneName}
            onChange={(e) => setNewSceneName(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleCreateScene()}
            className="w-full bg-slate-800 border border-slate-700 rounded-lg px-4 py-3 text-white placeholder:text-slate-500 focus:border-blue-500 outline-none"
            autoFocus
          />
        </ModalBody>
        <ModalFooter>
          <Button variant="ghost" onClick={() => setIsCreateModalOpen(false)}>
            Отмена
          </Button>
          <Button onClick={handleCreateScene} disabled={!newSceneName.trim()}>
            Создать
          </Button>
        </ModalFooter>
      </Modal>
    </div>
  );
};
