import { useEffect, useRef, useCallback } from 'react';
import { useAuthStore } from '@/stores';

const API_URL = '/.netlify/functions/remote-command';

interface RemoteCommand {
  type:
    | 'TOGGLE_PLAY'
    | 'SET_SPEED'
    | 'RESET'
    | 'SCROLL_UP'
    | 'SCROLL_DOWN'
    | 'TOGGLE_RECORDING'
    | 'PLAY_SOUND'
    | 'TOGGLE_LOWER_THIRD'
    | 'TOGGLE_TICKER';
  payload?: string | number;
}

// Hook for SENDING commands (mobile remote)
export function useBroadcastSender() {
  const pinCode = useAuthStore((s) => s.pinCode);

  const sendCommand = useCallback(async (type: RemoteCommand['type'], payload?: string | number) => {
    const command: RemoteCommand = { type, payload };

    try {
      await fetch(API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ room: pinCode, command }),
      });
    } catch (err) {
      console.error('Failed to send remote command:', err);
    }
  }, [pinCode]);

  return {
    // Prompter controls
    togglePlay: () => sendCommand('TOGGLE_PLAY'),
    setSpeed: (speed: number) => sendCommand('SET_SPEED', speed),
    reset: () => sendCommand('RESET'),
    scrollUp: () => sendCommand('SCROLL_UP'),
    scrollDown: () => sendCommand('SCROLL_DOWN'),
    // Recording
    toggleRecording: () => sendCommand('TOGGLE_RECORDING'),
    // Sound effects
    playSound: (soundId: string) => sendCommand('PLAY_SOUND', soundId),
    // Overlays
    toggleLowerThird: () => sendCommand('TOGGLE_LOWER_THIRD'),
    toggleTicker: () => sendCommand('TOGGLE_TICKER'),
  };
}

// Hook for RECEIVING commands (studio)
export function useBroadcastReceiver(handlers: {
  onTogglePlay?: () => void;
  onSetSpeed?: (speed: number) => void;
  onReset?: () => void;
  onScrollUp?: () => void;
  onScrollDown?: () => void;
  onToggleRecording?: () => void;
  onPlaySound?: (soundId: string) => void;
  onToggleLowerThird?: () => void;
  onToggleTicker?: () => void;
}) {
  const handlersRef = useRef(handlers);
  const lastTimestampRef = useRef(Date.now());
  const pinCode = useAuthStore((s) => s.pinCode);

  handlersRef.current = handlers;

  useEffect(() => {
    if (typeof window === 'undefined') return;

    let isActive = true;

    // Poll for commands every 500ms
    const poll = async () => {
      if (!isActive) return;

      try {
        const url = `${API_URL}?room=${encodeURIComponent(pinCode)}&since=${lastTimestampRef.current}`;
        const response = await fetch(url);
        const data = await response.json();

        if (data.command && data.timestamp > lastTimestampRef.current) {
          lastTimestampRef.current = data.timestamp;

          const command = data.command as RemoteCommand;
          switch (command.type) {
            case 'TOGGLE_PLAY':
              handlersRef.current.onTogglePlay?.();
              break;
            case 'SET_SPEED':
              if (typeof command.payload === 'number') {
                handlersRef.current.onSetSpeed?.(command.payload);
              }
              break;
            case 'RESET':
              handlersRef.current.onReset?.();
              break;
            case 'SCROLL_UP':
              handlersRef.current.onScrollUp?.();
              break;
            case 'SCROLL_DOWN':
              handlersRef.current.onScrollDown?.();
              break;
            case 'TOGGLE_RECORDING':
              handlersRef.current.onToggleRecording?.();
              break;
            case 'PLAY_SOUND':
              if (typeof command.payload === 'string') {
                handlersRef.current.onPlaySound?.(command.payload);
              }
              break;
            case 'TOGGLE_LOWER_THIRD':
              handlersRef.current.onToggleLowerThird?.();
              break;
            case 'TOGGLE_TICKER':
              handlersRef.current.onToggleTicker?.();
              break;
          }
        }
      } catch (err) {
        console.error('Failed to poll for commands:', err);
      }

      // Continue polling
      if (isActive) {
        setTimeout(poll, 500);
      }
    };

    // Start polling
    poll();

    return () => {
      isActive = false;
    };
  }, [pinCode]);
}
