import type { VideoSettings, VirtualBackground } from './video';
import type { AudioSettings } from './audio';
import type { OverlayState } from './overlay';
import type { PrompterSettings } from './prompter';

export interface Scene {
  id: string;
  name: string;
  thumbnail: string | null;
  video: VideoSettings & { virtualBackground: VirtualBackground };
  audio: AudioSettings;
  overlay: OverlayState;
  prompter: PrompterSettings;
  createdAt: number;
  updatedAt: number;
}

export interface SceneState {
  scenes: Scene[];
  activeSceneId: string | null;
}

export const createSceneId = (): string => {
  return `scene_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
};
