import { useRef, useEffect, useCallback } from 'react';
import { useRecordingStore } from '@/stores';

interface UseRecorderOptions {
  canvasRef: React.RefObject<HTMLCanvasElement | null>;
  audioDestination: MediaStreamAudioDestinationNode | null;
}

export function useRecorder({ canvasRef, audioDestination }: UseRecorderOptions) {
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerRef = useRef<number | null>(null);
  const canvasStreamRef = useRef<MediaStream | null>(null);

  const {
    isRecording,
    isPaused,
    settings,
    start: storeStart,
    stop: storeStop,
    pause: storePause,
    resume: storeResume,
    addBlob,
    incrementDuration,
    clearBlobs,
  } = useRecordingStore();

  // Capture canvas stream
  const captureCanvasStream = useCallback((): MediaStream | null => {
    if (!canvasRef.current) return null;

    try {
      // Fixed 30fps for consistent capture (matches common video standards)
      const stream = canvasRef.current.captureStream(30);
      canvasStreamRef.current = stream;
      return stream;
    } catch (err) {
      console.error('Failed to capture canvas stream:', err);
      return null;
    }
  }, [canvasRef]);

  // Start recording
  const start = useCallback(() => {
    const canvasStream = captureCanvasStream();
    if (!canvasStream) {
      console.error('No canvas stream available');
      return;
    }

    // Combine video and audio tracks
    const tracks: MediaStreamTrack[] = [...canvasStream.getVideoTracks()];

    if (settings.includeAudio && audioDestination) {
      tracks.push(...audioDestination.stream.getAudioTracks());
    }

    const combinedStream = new MediaStream(tracks);

    // Determine MIME type - prefer MP4 for wider compatibility
    const preferredMimeTypes = [
      'video/mp4;codecs=avc1.42E01E,mp4a.40.2',
      'video/mp4',
      'video/webm;codecs=vp9,opus',
      'video/webm;codecs=vp8,opus',
      'video/webm',
    ];

    const actualMimeType = preferredMimeTypes.find(type =>
      MediaRecorder.isTypeSupported(type)
    ) || 'video/webm';

    try {
      const recorder = new MediaRecorder(combinedStream, {
        mimeType: actualMimeType,
        videoBitsPerSecond: settings.videoBitrate,
        audioBitsPerSecond: settings.audioBitrate,
      });

      recorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          addBlob(event.data);
        }
      };

      recorder.onstop = () => {
        // Timer cleanup happens in stop()
      };

      recorder.onerror = (event) => {
        console.error('MediaRecorder error:', event);
        stop();
      };

      mediaRecorderRef.current = recorder;
      // Use 2000ms timeslice - better for long recordings (fewer blobs in memory)
      // A/V sync is handled at encoder level, not by timeslice frequency
      recorder.start(2000);

      // Start timer
      timerRef.current = window.setInterval(() => {
        incrementDuration();
      }, 1000);

      storeStart();
    } catch (err) {
      console.error('Failed to start recording:', err);
    }
  }, [
    captureCanvasStream,
    audioDestination,
    settings,
    addBlob,
    incrementDuration,
    storeStart,
  ]);

  // Stop recording
  const stop = useCallback(() => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
    }

    if (timerRef.current) {
      clearInterval(timerRef.current);
      timerRef.current = null;
    }

    storeStop();
  }, [storeStop]);

  // Pause recording
  const pause = useCallback(() => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.pause();
      storePause();
    }
  }, [storePause]);

  // Resume recording
  const resume = useCallback(() => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'paused') {
      mediaRecorderRef.current.resume();
      storeResume();
    }
  }, [storeResume]);

  // Download recorded video
  const download = useCallback((filename?: string) => {
    const { recordedBlobs } = useRecordingStore.getState();

    if (recordedBlobs.length === 0) {
      console.warn('No recorded data to download');
      return;
    }

    // Detect format from first blob's type
    const firstBlob = recordedBlobs[0];
    const isMP4 = firstBlob.type.includes('mp4');
    const format = isMP4 ? 'mp4' : 'webm';
    const mimeType = isMP4 ? 'video/mp4' : 'video/webm';

    const blob = new Blob(recordedBlobs, { type: mimeType });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = filename || `kazarian-sufler-${Date.now()}.${format}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);

    URL.revokeObjectURL(url);
    clearBlobs();
  }, [clearBlobs]);

  // Get recorded blob
  const getBlob = useCallback((): Blob | null => {
    const { recordedBlobs } = useRecordingStore.getState();

    if (recordedBlobs.length === 0) return null;

    // Detect format from first blob's type
    const firstBlob = recordedBlobs[0];
    const mimeType = firstBlob.type.includes('mp4') ? 'video/mp4' : 'video/webm';
    return new Blob(recordedBlobs, { type: mimeType });
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
        mediaRecorderRef.current.stop();
      }
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
      if (canvasStreamRef.current) {
        canvasStreamRef.current.getTracks().forEach((t) => t.stop());
      }
    };
  }, []);

  return {
    isRecording,
    isPaused,
    start,
    stop,
    pause,
    resume,
    download,
    getBlob,
  };
}
