import type { Scene } from './scene';
import type { VideoSettings, VirtualBackground } from './video';
import type { AudioSettings } from './audio';

export interface ProjectMetadata {
  id: string;
  name: string;
  createdAt: number;
  updatedAt: number;
  version: string;
}

export interface Project extends ProjectMetadata {
  scenes: Scene[];
  globalSettings: {
    video: VideoSettings & { virtualBackground: VirtualBackground };
    audio: AudioSettings;
  };
}

export interface ProjectListItem {
  id: string;
  name: string;
  updatedAt: number;
  sceneCount: number;
}

export interface ProjectState {
  currentProject: Project | null;
  projects: ProjectListItem[];
  isDirty: boolean;
  lastSavedAt: number | null;
}

export const PROJECT_VERSION = '1.0.0';
export const STORAGE_KEY_PROJECTS = 'kazarian_projects';
export const STORAGE_KEY_CURRENT_PROJECT = 'kazarian_current_project';
export const AUTO_SAVE_INTERVAL = 30000; // 30 seconds

export const createProjectId = (): string => {
  return `project_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
};
