import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { VideoState, VideoSettings, VirtualBackground } from '@/types';
import { DEFAULT_VIDEO_SETTINGS, DEFAULT_VIRTUAL_BACKGROUND } from '@/types';

interface VideoActions {
  updateSettings: (settings: Partial<VideoSettings>) => void;
  updateVirtualBackground: (bg: Partial<VirtualBackground>) => void;
  setDevice: (deviceId: string) => void;
  setDevices: (devices: MediaDeviceInfo[]) => void;
  toggleMirror: () => void;
  setAspectRatio: (ratio: VideoState['aspectRatio']) => void;
  reset: () => void;
}

const initialState: VideoState = {
  ...DEFAULT_VIDEO_SETTINGS,
  virtualBackground: DEFAULT_VIRTUAL_BACKGROUND,
  selectedDeviceId: '',
  devices: [],
  isMirrored: false,
  aspectRatio: '16:9',
};

export const useVideoStore = create<VideoState & VideoActions>()(
  persist(
    (set) => ({
      ...initialState,

      updateSettings: (settings) =>
        set((state) => ({
          ...state,
          ...settings,
        })),

      updateVirtualBackground: (bg) =>
        set((state) => ({
          virtualBackground: {
            ...state.virtualBackground,
            ...bg,
          },
        })),

      setDevice: (deviceId) =>
        set({ selectedDeviceId: deviceId }),

      setDevices: (devices) =>
        set((state) => {
          const newState: Partial<VideoState> = { devices };
          if (!state.selectedDeviceId && devices.length > 0) {
            newState.selectedDeviceId = devices[0].deviceId;
          }
          return newState;
        }),

      toggleMirror: () =>
        set((state) => ({ isMirrored: !state.isMirrored })),

      setAspectRatio: (aspectRatio) =>
        set({ aspectRatio }),

      reset: () =>
        set({
          ...DEFAULT_VIDEO_SETTINGS,
          virtualBackground: DEFAULT_VIRTUAL_BACKGROUND,
          isMirrored: false,
          aspectRatio: '16:9',
        }),
    }),
    {
      name: 'kazarian-video-settings',
      partialize: (state) => ({
        brightness: state.brightness,
        contrast: state.contrast,
        saturation: state.saturation,
        blur: state.blur,
        vignette: state.vignette,
        faceLight: state.faceLight,
        virtualBackground: state.virtualBackground,
        isMirrored: state.isMirrored,
        aspectRatio: state.aspectRatio,
      }),
    }
  )
);
