import { useRef, useCallback, useEffect } from 'react';

interface UsePresentationModeOptions {
  canvasRef: React.RefObject<HTMLCanvasElement | null>;
}

export function usePresentationMode({ canvasRef }: UsePresentationModeOptions) {
  const presentationWindowRef = useRef<Window | null>(null);
  const animationRef = useRef<number | null>(null);

  const openPresentationWindow = useCallback(() => {
    if (!canvasRef.current) return;

    const sourceCanvas = canvasRef.current;
    const sourceWidth = sourceCanvas.width;
    const sourceHeight = sourceCanvas.height;

    // Open at smaller size (640x360 for 16:9) - user can resize
    const windowWidth = 640;
    const windowHeight = 360;

    // Calculate window position (center of screen)
    const left = (window.screen.width - windowWidth) / 2;
    const top = (window.screen.height - windowHeight) / 2;

    // Open new window - resizable enabled
    const presentationWindow = window.open(
      '',
      'KazarianStudio_Presentation',
      `width=${windowWidth},height=${windowHeight},left=${left},top=${top},menubar=no,toolbar=no,location=no,status=no,resizable=yes`
    );

    if (!presentationWindow) {
      alert('Не удалось открыть окно презентации. Разрешите всплывающие окна.');
      return;
    }

    presentationWindowRef.current = presentationWindow;

    // Setup presentation window - exact copy of source canvas
    presentationWindow.document.write(`
      <!DOCTYPE html>
      <html>
        <head>
          <title>Kazarian Studio - Zoom</title>
          <style>
            * { margin: 0; padding: 0; }
            body { background: #000; }
            canvas { display: block; width: 100%; height: auto; }
          </style>
        </head>
        <body>
          <canvas id="presentationCanvas" width="${sourceWidth}" height="${sourceHeight}"></canvas>
        </body>
      </html>
    `);
    presentationWindow.document.close();

    // Get destination canvas
    const destCanvas = presentationWindow.document.getElementById('presentationCanvas') as HTMLCanvasElement;
    if (!destCanvas) return;

    const destCtx = destCanvas.getContext('2d');
    if (!destCtx) return;

    // Mirror the source canvas to presentation window
    const mirrorCanvas = () => {
      if (!presentationWindow || presentationWindow.closed) {
        if (animationRef.current) {
          cancelAnimationFrame(animationRef.current);
          animationRef.current = null;
        }
        presentationWindowRef.current = null;
        return;
      }

      if (sourceCanvas && destCtx) {
        destCtx.drawImage(sourceCanvas, 0, 0);
      }

      animationRef.current = requestAnimationFrame(mirrorCanvas);
    };

    mirrorCanvas();

    // Handle window close
    presentationWindow.onbeforeunload = () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
        animationRef.current = null;
      }
      presentationWindowRef.current = null;
    };

  }, [canvasRef]);

  const closePresentationWindow = useCallback(() => {
    if (presentationWindowRef.current && !presentationWindowRef.current.closed) {
      presentationWindowRef.current.close();
    }
    if (animationRef.current) {
      cancelAnimationFrame(animationRef.current);
      animationRef.current = null;
    }
    presentationWindowRef.current = null;
  }, []);

  const isPresentationOpen = useCallback(() => {
    return presentationWindowRef.current !== null && !presentationWindowRef.current.closed;
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      closePresentationWindow();
    };
  }, [closePresentationWindow]);

  return {
    openPresentationWindow,
    closePresentationWindow,
    isPresentationOpen,
  };
}
