interface UseSoundEffectsOptions {
  volume?: number;
  onEnded?: (effectId: string) => void;
  // For recording - route audio through these nodes
  audioContext?: AudioContext | null;
  audioDestination?: MediaStreamAudioDestinationNode | null;
}

// Synthesized sound patterns for fallback
const SYNTH_SOUNDS: Record<string, { frequencies: number[]; durations: number[]; type: OscillatorType }> = {
  applause: { frequencies: [200, 300, 250, 350, 280], durations: [100, 100, 100, 100, 100], type: 'sawtooth' },
  laugh: { frequencies: [400, 350, 400, 350, 400], durations: [150, 100, 150, 100, 150], type: 'sine' },
  correct: { frequencies: [523, 659, 784], durations: [100, 100, 200], type: 'sine' },
  plashka: { frequencies: [1000, 500, 200], durations: [50, 50, 100], type: 'sawtooth' },
  'drum-roll': { frequencies: [150, 160, 150, 160, 150, 160, 150, 160], durations: [50, 50, 50, 50, 50, 50, 50, 50], type: 'triangle' },
  'sad-trombone': { frequencies: [392, 349, 311, 262], durations: [300, 300, 300, 500], type: 'sawtooth' },
};

export function useSoundEffects(options: UseSoundEffectsOptions = {}) {
  const { volume = 1.0, onEnded, audioContext: externalCtx, audioDestination } = options;
  const audioRefs = useRef<Map<string, HTMLAudioElement>>(new Map());
  const sourceNodesRef = useRef<Map<string, MediaElementAudioSourceNode>>(new Map());
  const loadedSounds = useRef<Set<string>>(new Set());
  const audioContextRef = useRef<AudioContext | null>(null);
  const onEndedRef = useRef(onEnded);
  const [isLoaded, setIsLoaded] = useState(false);

  // Keep onEnded ref updated
  useEffect(() => {
    onEndedRef.current = onEnded;
  }, [onEnded]);

  // Get or create AudioContext (prefer external context for recording)
  const getAudioContext = useCallback(() => {
    // Use external context if available (for recording)
    if (externalCtx && externalCtx.state !== 'closed') {
      if (externalCtx.state === 'suspended') {
        externalCtx.resume();
      }
      return externalCtx;
    }
    // Fallback to internal context
    if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
      audioContextRef.current = new AudioContext();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
    return audioContextRef.current;
  }, [externalCtx]);

  // Preload sounds
  useEffect(() => {
    let mounted = true;

    SOUND_EFFECTS.forEach((effect) => {
      if (!audioRefs.current.has(effect.id)) {
        const audio = new Audio();
        audio.preload = 'auto';
        audio.volume = volume;

        audio.oncanplaythrough = () => {
          if (mounted) {
            loadedSounds.current.add(effect.id);
            if (loadedSounds.current.size === SOUND_EFFECTS.length) {
              setIsLoaded(true);
            }
          }
        };

        audio.onended = () => {
          if (mounted && onEndedRef.current) {
            onEndedRef.current(effect.id);
          }
        };

        audio.onerror = () => {
          console.warn(`Sound file not found: ${effect.url}, using synthesized sound`);
        };

        audio.src = effect.url;
        audioRefs.current.set(effect.id, audio);
      }
    });

    return () => {
      mounted = false;
      audioRefs.current.forEach((audio) => {
        audio.pause();
        audio.src = '';
      });
      audioRefs.current.clear();
      loadedSounds.current.clear();
    };
  }, [volume]);

  // Update volume when it changes
  useEffect(() => {
    audioRefs.current.forEach((audio) => {
      audio.volume = volume;
    });
  }, [volume]);

  // Play synthesized sound as fallback
  const playSynthSound = useCallback(
    (effectId: string) => {
      const pattern = SYNTH_SOUNDS[effectId];
      if (!pattern) return;

      const ctx = getAudioContext();
      let time = ctx.currentTime;

      pattern.frequencies.forEach((freq, i) => {
        const oscillator = ctx.createOscillator();
        const gainNode = ctx.createGain();

        oscillator.connect(gainNode);
        // Connect to both destination (speakers) and recording destination
        gainNode.connect(ctx.destination);
        if (audioDestination) {
          gainNode.connect(audioDestination);
        }

        oscillator.frequency.value = freq;
        oscillator.type = pattern.type;

        const duration = pattern.durations[i] / 1000;

        gainNode.gain.setValueAtTime(volume * 0.2, time);
        gainNode.gain.exponentialRampToValueAtTime(0.01, time + duration);

        oscillator.start(time);
        oscillator.stop(time + duration);

        time += duration * 0.8; // Slight overlap for smoother sound
      });
    },
    [volume, getAudioContext, audioDestination]
  );

  // Play a sound effect
  const play = useCallback(
    (effectId: string) => {
      const audio = audioRefs.current.get(effectId);

      // Try to play the actual audio file
      if (audio && loadedSounds.current.has(effectId)) {
        audio.currentTime = 0;

        // If we have an external context and destination, route through Web Audio API for recording
        if (externalCtx && audioDestination && externalCtx.state !== 'closed') {
          // Create source node if not already created
          if (!sourceNodesRef.current.has(effectId)) {
            try {
              const sourceNode = externalCtx.createMediaElementSource(audio);
              const gainNode = externalCtx.createGain();
              gainNode.gain.value = 1;

              sourceNode.connect(gainNode);
              // Connect to both speakers and recording destination
              gainNode.connect(externalCtx.destination);
              gainNode.connect(audioDestination);

              sourceNodesRef.current.set(effectId, sourceNode);
            } catch {
              // If MediaElementSource already exists, just play normally
            }
          }
        }

        audio.play().catch(() => {
          // Fallback to synthesized sound if playback fails
          playSynthSound(effectId);
        });
      } else {
        // Use synthesized sound if file not loaded
        playSynthSound(effectId);
      }
    },
    [playSynthSound, externalCtx, audioDestination]
  );

  // Stop a specific sound
  const stop = useCallback((effectId: string) => {
    const audio = audioRefs.current.get(effectId);
    if (audio) {
      audio.pause();
      audio.currentTime = 0;
    }
  }, []);

  // Stop all sounds
  const stopAll = useCallback(() => {
    audioRefs.current.forEach((audio) => {
      audio.pause();
      audio.currentTime = 0;
    });
  }, []);

  // Generate a simple beep
  const playBeep = useCallback(
    (frequency = 440, duration = 200) => {
      const ctx = getAudioContext();

      const oscillator = ctx.createOscillator();
      const gainNode = ctx.createGain();

      oscillator.connect(gainNode);
      // Connect to both speakers and recording destination
      gainNode.connect(ctx.destination);
      if (audioDestination) {
        gainNode.connect(audioDestination);
      }

      oscillator.frequency.value = frequency;
      oscillator.type = 'sine';

      gainNode.gain.setValueAtTime(volume * 0.3, ctx.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + duration / 1000);

      oscillator.start(ctx.currentTime);
      oscillator.stop(ctx.currentTime + duration / 1000);
    },
    [volume, getAudioContext, audioDestination]
  );

  return {
    effects: SOUND_EFFECTS,
    play,
    stop,
    stopAll,
    playBeep,
    isLoaded,
  };
}
