import React, { useRef, useEffect, useState, useCallback } from 'react';
import { clsx } from 'clsx';
import { Play, Pause, Mic, MicOff, Settings, X, Activity, Volume2 } from 'lucide-react';
import { usePrompterStore, useAudioStore } from '@/stores';
import { useVoiceActivity } from '@/hooks';
import { Slider } from '@/components/common';

export const Teleprompter: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const animationRef = useRef<number | null>(null);
  const lastTimeRef = useRef<number>(0);
  const voiceAnimationRef = useRef<number | null>(null);
  const voiceLastTimeRef = useRef<number>(0);

  const [showSettings, setShowSettings] = useState(false);

  // Store values
  const {
    text,
    fontSize,
    speed,
    isPlaying,
    opacity,
    mirror,
    width,
    voiceScroll,
    voiceSensitivity,
    updateSettings,
    toggle,
    toggleVoiceScroll,
  } = usePrompterStore();

  const audioDeviceId = useAudioStore((s) => s.selectedDeviceId);

  // Voice activity detection
  const handleVoiceScroll = useCallback(() => {
    if (containerRef.current) {
      const baseSpeed = speed > 0 ? speed : 2.5;
      const increment = baseSpeed * 0.5;
      containerRef.current.scrollTop += increment;
    }
  }, [speed]);

  const { isTalking, volume, start: startVAD, stop: stopVAD } = useVoiceActivity({
    deviceId: audioDeviceId,
    threshold: voiceSensitivity,
    onVoiceStart: handleVoiceScroll,
  });

  // Start/stop VAD based on voiceScroll setting
  useEffect(() => {
    if (voiceScroll) {
      startVAD();
    } else {
      stopVAD();
    }
  }, [voiceScroll, startVAD, stopVAD]);

  // Standard auto-scroll using requestAnimationFrame for smooth animation
  useEffect(() => {
    if (isPlaying && speed > 0 && !voiceScroll) {
      const animate = (currentTime: number) => {
        if (!containerRef.current) return;

        // Calculate delta time for consistent speed regardless of frame rate
        const deltaTime = lastTimeRef.current ? (currentTime - lastTimeRef.current) / 1000 : 0;
        lastTimeRef.current = currentTime;

        // Speed is pixels per 30ms, convert to pixels per second then apply delta
        const pixelsPerSecond = (speed / 30) * 1000;
        const scrollAmount = pixelsPerSecond * deltaTime;

        if (scrollAmount > 0) {
          containerRef.current.scrollTop += scrollAmount;
        }

        animationRef.current = requestAnimationFrame(animate);
      };

      lastTimeRef.current = 0;
      animationRef.current = requestAnimationFrame(animate);
    } else {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
        animationRef.current = null;
      }
      lastTimeRef.current = 0;
    }

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [isPlaying, speed, voiceScroll]);

  // Keyboard controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (target.tagName === 'TEXTAREA' || target.tagName === 'INPUT' || target.isContentEditable) {
        return;
      }

      if (e.code === 'Space') {
        e.preventDefault();
        if (!voiceScroll) {
          toggle();
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [voiceScroll, toggle]);

  // Continuous voice scroll effect using requestAnimationFrame
  useEffect(() => {
    if (voiceScroll && isTalking) {
      const animateVoice = (currentTime: number) => {
        if (!containerRef.current) return;

        const deltaTime = voiceLastTimeRef.current ? (currentTime - voiceLastTimeRef.current) / 1000 : 0;
        voiceLastTimeRef.current = currentTime;

        const baseSpeed = speed > 0 ? speed : 2.5;
        // Convert to pixels per second and apply delta
        const pixelsPerSecond = (baseSpeed / 30) * 1000 * 0.8; // Slightly slower than auto-scroll
        const scrollAmount = pixelsPerSecond * deltaTime;

        if (scrollAmount > 0) {
          containerRef.current.scrollTop += scrollAmount;
        }

        voiceAnimationRef.current = requestAnimationFrame(animateVoice);
      };

      voiceLastTimeRef.current = 0;
      voiceAnimationRef.current = requestAnimationFrame(animateVoice);
    } else {
      if (voiceAnimationRef.current) {
        cancelAnimationFrame(voiceAnimationRef.current);
        voiceAnimationRef.current = null;
      }
      voiceLastTimeRef.current = 0;
    }

    return () => {
      if (voiceAnimationRef.current) {
        cancelAnimationFrame(voiceAnimationRef.current);
      }
    };
  }, [voiceScroll, isTalking, speed]);

  const lines = text.split('\n');

  return (
    <div className="absolute inset-0 z-20 pointer-events-none flex justify-center items-center">
      {/* Prompter Container */}
      <div
        style={{ width: `${width}%`, opacity }}
        className="h-full relative pointer-events-auto bg-black/30 backdrop-blur-sm transition-all duration-300"
      >
        {/* Eye Level Marker */}
        <div className="absolute top-1/3 left-0 w-full z-30 flex flex-col items-center pointer-events-none">
          <div className="w-full h-0.5 bg-red-500/50 flex items-center relative">
            <div className="bg-red-500 text-[10px] text-white px-1 ml-1 rounded font-bold">
              УРОВЕНЬ ГЛАЗ
            </div>

            {/* Voice Status */}
            {voiceScroll && (
              <div className="absolute right-0 top-[-36px] mr-2 flex flex-col items-end pointer-events-auto">
                {/* Threshold Slider */}
                <div className="flex items-center gap-2 px-3 py-1 mb-1 rounded-full border shadow-lg backdrop-blur-md bg-slate-900/90 border-slate-700">
                  <span className="text-[10px] text-slate-400 font-bold uppercase mr-1">
                    Порог
                  </span>
                  <input
                    type="range"
                    min="1"
                    max="50"
                    step="1"
                    value={voiceSensitivity}
                    onChange={(e) => updateSettings({ voiceSensitivity: Number(e.target.value) })}
                    className="w-16 h-1 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-blue-500"
                  />
                  <span className="text-[10px] font-mono text-slate-300 w-4">
                    {voiceSensitivity}
                  </span>
                </div>

                {/* Status Bar */}
                <div
                  className={clsx(
                    'flex items-center gap-2 px-3 py-1 rounded-full border shadow-lg backdrop-blur-md transition-colors duration-200',
                    isTalking
                      ? 'bg-green-600/90 border-green-400 text-white'
                      : 'bg-slate-800/80 border-slate-600 text-slate-400'
                  )}
                >
                  {isTalking ? (
                    <Activity size={14} className="animate-pulse" />
                  ) : (
                    <MicOff size={14} />
                  )}
                  <span className="text-xs font-bold whitespace-nowrap w-16 text-center">
                    {isTalking ? 'ЕХАЛИ!' : 'ЖДУ...'}
                  </span>
                  {/* Volume Bar */}
                  <div className="w-16 h-2 bg-black/50 rounded-full overflow-hidden ml-1 relative">
                    <div
                      className="absolute top-0 bottom-0 w-0.5 bg-red-500 z-10"
                      style={{ left: `${voiceSensitivity}%` }}
                    />
                    <div
                      className={clsx(
                        'h-full transition-all duration-75',
                        isTalking ? 'bg-white' : 'bg-slate-500'
                      )}
                      style={{ width: `${Math.min(100, volume)}%` }}
                    />
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Text Container */}
        <div
          ref={containerRef}
          className={clsx(
            'w-full h-full overflow-y-auto no-scrollbar p-8 text-center font-semibold text-white leading-relaxed',
            mirror && 'scale-x-[-1]'
          )}
          style={{ fontSize: `${fontSize}px`, textShadow: '2px 2px 4px black' }}
        >
          <div className="h-[30vh]" />
          {lines.map((line, i) => (
            <p key={i} className="mb-6">
              {line}
            </p>
          ))}
          <div className="h-[60vh]" />
        </div>
      </div>

      {/* Floating Controls */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex flex-col items-center pointer-events-auto z-50">
        {/* Settings Panel */}
        {showSettings && (
          <div className="bg-slate-900/95 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-2xl mb-4 w-72 text-white animate-slide-up">
            <div className="flex justify-between items-center mb-4 pb-2 border-b border-slate-700">
              <span className="font-semibold text-sm">Настройки суфлера</span>
              <button
                onClick={() => setShowSettings(false)}
                className="text-slate-400 hover:text-white"
              >
                <X size={16} />
              </button>
            </div>

            <div className="space-y-4">
              <Slider
                label="Размер шрифта"
                value={fontSize}
                min={20}
                max={150}
                unit="px"
                onChange={(v) => updateSettings({ fontSize: v })}
              />
              <Slider
                label="Ширина текста"
                value={width}
                min={20}
                max={100}
                unit="%"
                onChange={(v) => updateSettings({ width: v })}
              />
              <Slider
                label="Прозрачность фона"
                value={Math.round(opacity * 100)}
                min={0}
                max={100}
                unit="%"
                onChange={(v) => updateSettings({ opacity: v / 100 })}
              />
            </div>
          </div>
        )}

        {/* Control Bar */}
        <div
          className="flex items-center gap-3 bg-slate-900/80 backdrop-blur-md p-2 pl-4 pr-2 rounded-full border border-slate-700/50 shadow-xl transition-all duration-300 hover:bg-slate-900"
        >
          {/* Play/Pause */}
          <button
            onClick={() => !voiceScroll && toggle()}
            disabled={voiceScroll}
            className={clsx(
              'flex items-center justify-center w-10 h-10 rounded-full text-white transition-colors',
              voiceScroll
                ? 'opacity-30 cursor-not-allowed bg-slate-800'
                : 'hover:bg-slate-700'
            )}
            title={voiceScroll ? 'Отключите голос для авто-прокрутки' : 'Старт/Пауза'}
          >
            {isPlaying ? (
              <Pause size={20} fill="currentColor" />
            ) : (
              <Play size={20} fill="currentColor" className="ml-0.5" />
            )}
          </button>

          {/* Speed */}
          <div className="flex items-center gap-2 px-2 border-l border-r border-slate-700/50 h-8">
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
              Скорость
            </span>
            <input
              type="range"
              min="0"
              max="5"
              step="0.1"
              value={speed}
              onChange={(e) => updateSettings({ speed: parseFloat(e.target.value) })}
              className="w-24 h-1 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
            <span className="text-xs font-mono text-slate-300 w-6 text-right">
              {speed.toFixed(1)}
            </span>
          </div>

          {/* Voice Scroll Toggle */}
          <button
            onClick={toggleVoiceScroll}
            className={clsx(
              'flex items-center justify-center w-10 h-10 rounded-full transition-all',
              voiceScroll
                ? 'bg-green-500 text-black shadow-[0_0_15px_rgba(34,197,94,0.5)]'
                : 'hover:bg-slate-700 text-slate-300'
            )}
            title="Активация голосом"
          >
            {voiceScroll ? <Volume2 size={20} /> : <Mic size={18} />}
          </button>

          {/* Settings */}
          <button
            onClick={() => setShowSettings(!showSettings)}
            className={clsx(
              'flex items-center justify-center w-10 h-10 rounded-full transition-all',
              showSettings
                ? 'bg-blue-600 text-white'
                : 'hover:bg-slate-700 text-slate-300'
            )}
          >
            <Settings size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};
