import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { PrompterState, PrompterSettings } from '@/types';
import { DEFAULT_PROMPTER_SETTINGS, WORDS_PER_MINUTE } from '@/types';

interface PrompterActions {
  updateSettings: (settings: Partial<PrompterSettings>) => void;
  setText: (text: string) => void;
  setScrollPosition: (position: number) => void;
  setHighlightLine: (index: number) => void;
  setSpeed: (speed: number) => void;
  play: () => void;
  pause: () => void;
  toggle: () => void;
  togglePlay: () => void;
  toggleMirror: () => void;
  toggleVoiceScroll: () => void;
  reset: () => void;
  resetPosition: () => void;
  scrollUp: () => void;
  scrollDown: () => void;
}

const calculateReadTime = (text: string): number => {
  const words = text.split(/\s+/).filter(Boolean).length;
  return Math.ceil((words / WORDS_PER_MINUTE) * 60);
};

const initialState: PrompterState = {
  ...DEFAULT_PROMPTER_SETTINGS,
  scrollPosition: 0,
  highlightLineIndex: 0,
  estimatedReadTime: calculateReadTime(DEFAULT_PROMPTER_SETTINGS.text),
};

export const usePrompterStore = create<PrompterState & PrompterActions>()(
  persist(
    (set) => ({
      ...initialState,

      updateSettings: (settings) =>
        set((state) => {
          const newState = { ...state, ...settings };
          if (settings.text !== undefined) {
            newState.estimatedReadTime = calculateReadTime(settings.text);
          }
          return newState;
        }),

      setText: (text) =>
        set({
          text,
          estimatedReadTime: calculateReadTime(text),
          scrollPosition: 0,
          highlightLineIndex: 0,
        }),

      setScrollPosition: (position) =>
        set({ scrollPosition: position }),

      setHighlightLine: (index) =>
        set({ highlightLineIndex: index }),

      play: () =>
        set({ isPlaying: true }),

      pause: () =>
        set({ isPlaying: false }),

      toggle: () =>
        set((state) => ({ isPlaying: !state.isPlaying })),

      togglePlay: () =>
        set((state) => ({ isPlaying: !state.isPlaying })),

      setSpeed: (speed) =>
        set({ speed }),

      scrollUp: () =>
        set((state) => ({ scrollPosition: Math.max(0, state.scrollPosition - 50) })),

      scrollDown: () =>
        set((state) => ({ scrollPosition: state.scrollPosition + 50 })),

      toggleMirror: () =>
        set((state) => ({ mirror: !state.mirror })),

      toggleVoiceScroll: () =>
        set((state) => ({
          voiceScroll: !state.voiceScroll,
          isPlaying: false,
        })),

      reset: () =>
        set({
          ...DEFAULT_PROMPTER_SETTINGS,
          scrollPosition: 0,
          highlightLineIndex: 0,
          estimatedReadTime: calculateReadTime(DEFAULT_PROMPTER_SETTINGS.text),
        }),

      resetPosition: () =>
        set({
          scrollPosition: 0,
          highlightLineIndex: 0,
          isPlaying: false,
        }),
    }),
    {
      name: 'kazarian-prompter-settings',
      partialize: (state) => ({
        text: state.text,
        fontSize: state.fontSize,
        speed: state.speed,
        opacity: state.opacity,
        mirror: state.mirror,
        width: state.width,
        voiceScroll: state.voiceScroll,
        voiceSensitivity: state.voiceSensitivity,
      }),
    }
  )
);
