import React from 'react';
import { Slider, Toggle, Select } from '@/components/common';
import { useOverlayStore } from '@/stores';

export const GraphicsTab: React.FC = () => {
  const {
    lowerThird,
    ticker,
    logo,
    subtitles,
    updateLowerThird,
    updateTicker,
    updateLogo,
    updateSubtitles,
    toggleLowerThird,
    toggleTicker,
    toggleLogo,
    toggleSubtitles,
  } = useOverlayStore();

  return (
    <div className="space-y-6">
      <h3 className="text-lg font-semibold text-white mb-4">Графика эфира</h3>

      {/* Lower Third */}
      <div className="bg-slate-800 p-4 rounded-lg space-y-3">
        <div className="flex items-center justify-between">
          <span className="text-sm font-medium text-white">Нижняя плашка</span>
          <button
            onClick={toggleLowerThird}
            className={`px-2 py-1 text-xs rounded ${
              lowerThird.visible
                ? 'bg-green-600 text-white'
                : 'bg-slate-700 text-slate-400'
            }`}
          >
            {lowerThird.visible ? 'Видна' : 'Скрыта'}
          </button>
        </div>

        {/* Text inputs always visible */}
        <input
          className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:border-blue-500 outline-none"
          value={lowerThird.text1}
          onChange={(e) => updateLowerThird({ text1: e.target.value })}
          placeholder="Имя (напр. Павел Казарьян)"
        />
        <input
          className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:border-blue-500 outline-none"
          value={lowerThird.text2}
          onChange={(e) => updateLowerThird({ text2: e.target.value })}
          placeholder="Должность (напр. Психолог)"
        />
        <Select
          label="Стиль"
          value={lowerThird.style}
          options={[
            { value: 'modern', label: 'Модерн (Синий)' },
            { value: 'neon', label: 'Неон (Розовый)' },
            { value: 'glass', label: 'Стекло' },
            { value: 'minimal', label: 'Минимал' },
          ]}
          onChange={(v) => updateLowerThird({ style: v as typeof lowerThird.style })}
        />

        {/* Auto-show settings */}
        <div className="pt-3 border-t border-slate-700 space-y-2">
          <Toggle
            label="Автопоказ во время записи"
            checked={lowerThird.autoShow}
            onChange={(v) => updateLowerThird({ autoShow: v })}
          />

          {lowerThird.autoShow && (
            <div className="text-[10px] text-slate-400 space-y-1 pl-2">
              <p>• Появится через {lowerThird.autoShowDelay / 1000} сек после старта</p>
              <p>• Будет видна {lowerThird.autoShowDuration / 1000} сек</p>
              <p>• Повторится каждые {lowerThird.autoShowInterval / 60000} мин</p>
              <p>• Звук: {lowerThird.soundEffect || 'нет'}</p>
            </div>
          )}
        </div>
      </div>

      {/* Ticker */}
      <div className="bg-slate-800 p-4 rounded-lg space-y-3">
        <Toggle
          label="Бегущая строка"
          checked={ticker.visible}
          onChange={toggleTicker}
        />

        {ticker.visible && (
          <>
            <textarea
              className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:border-blue-500 outline-none h-20 resize-none"
              value={ticker.text}
              onChange={(e) => updateTicker({ text: e.target.value })}
              placeholder="Текст строки..."
            />
            <Slider
              label="Скорость"
              value={ticker.speed}
              min={0.5}
              max={3}
              step={0.1}
              onChange={(v) => updateTicker({ speed: v })}
            />
            <Slider
              label="Размер шрифта"
              value={ticker.fontSize}
              min={12}
              max={32}
              unit="px"
              onChange={(v) => updateTicker({ fontSize: v })}
            />
            <Select
              label="Позиция"
              value={ticker.position}
              options={[
                { value: 'top', label: 'Сверху' },
                { value: 'bottom', label: 'Снизу' },
              ]}
              onChange={(v) => updateTicker({ position: v as typeof ticker.position })}
            />
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="text-xs text-slate-400 mb-1 block">Цвет фона</label>
                <input
                  type="color"
                  className="w-full h-8 bg-slate-900 border border-slate-700 rounded cursor-pointer"
                  value={ticker.backgroundColor}
                  onChange={(e) => updateTicker({ backgroundColor: e.target.value })}
                />
              </div>
              <div>
                <label className="text-xs text-slate-400 mb-1 block">Цвет текста</label>
                <input
                  type="color"
                  className="w-full h-8 bg-slate-900 border border-slate-700 rounded cursor-pointer"
                  value={ticker.textColor}
                  onChange={(e) => updateTicker({ textColor: e.target.value })}
                />
              </div>
            </div>

            {/* Auto-show settings */}
            <div className="pt-3 border-t border-slate-700 space-y-2">
              <Toggle
                label="Автопоказ во время записи"
                checked={ticker.autoShow}
                onChange={(v) => updateTicker({ autoShow: v })}
              />

              {ticker.autoShow && (
                <div className="text-[10px] text-slate-400 space-y-1 pl-2">
                  <p>• Появится через {ticker.autoShowDelay / 1000} сек после старта</p>
                  <p>• Будет видна {ticker.autoShowDuration / 1000} сек</p>
                  <p>• Повторится каждые {ticker.autoShowInterval / 60000} мин</p>
                  <p>• Звук: {ticker.soundEffect || 'нет'}</p>
                </div>
              )}
            </div>
          </>
        )}
      </div>

      {/* Logo */}
      <div className="bg-slate-800 p-4 rounded-lg space-y-3">
        <Toggle
          label="Логотип бренда"
          checked={logo.visible}
          onChange={toggleLogo}
        />

        {logo.visible && (
          <>
            <input
              className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:border-blue-500 outline-none"
              value={logo.text}
              onChange={(e) => updateLogo({ text: e.target.value })}
              placeholder="Название бренда"
            />
            <Slider
              label="Прозрачность"
              value={Math.round(logo.opacity * 100)}
              min={0}
              max={100}
              unit="%"
              onChange={(v) => updateLogo({ opacity: v / 100 })}
            />
            <Select
              label="Позиция"
              value={logo.position}
              options={[
                { value: 'top-left', label: 'Сверху слева' },
                { value: 'top-right', label: 'Сверху справа' },
                { value: 'bottom-left', label: 'Снизу слева' },
                { value: 'bottom-right', label: 'Снизу справа' },
              ]}
              onChange={(v) => updateLogo({ position: v as typeof logo.position })}
            />
          </>
        )}
      </div>

      {/* Subtitles */}
      <div className="bg-slate-800 p-4 rounded-lg space-y-3">
        <Toggle
          label="Субтитры (бета)"
          checked={subtitles.enabled}
          onChange={toggleSubtitles}
        />

        {subtitles.enabled && (
          <>
            <Slider
              label="Размер шрифта"
              value={subtitles.fontSize}
              min={16}
              max={48}
              unit="px"
              onChange={(v) => updateSubtitles({ fontSize: v })}
            />
            <Select
              label="Позиция"
              value={subtitles.position}
              options={[
                { value: 'top', label: 'Сверху' },
                { value: 'center', label: 'По центру' },
                { value: 'bottom', label: 'Снизу' },
              ]}
              onChange={(v) => updateSubtitles({ position: v as typeof subtitles.position })}
            />
            <p className="text-[10px] text-slate-500">
              * Субтитры генерируются автоматически из речи
            </p>
          </>
        )}
      </div>
    </div>
  );
};
