import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { Project, ProjectState, ProjectListItem } from '@/types';
import {
  PROJECT_VERSION,
  STORAGE_KEY_PROJECTS,
  createProjectId,
} from '@/types';
import { useSceneStore } from './useSceneStore';
import { useVideoStore } from './useVideoStore';
import { useAudioStore } from './useAudioStore';

interface ProjectActions {
  createProject: (name: string) => Project;
  loadProject: (id: string) => boolean;
  saveProject: () => void;
  renameProject: (id: string, name: string) => void;
  deleteProject: (id: string) => void;
  exportProject: () => string;
  importProject: (json: string) => boolean;
  setDirty: (dirty: boolean) => void;
  refreshProjectList: () => void;
}

const initialState: ProjectState = {
  currentProject: null,
  projects: [],
  isDirty: false,
  lastSavedAt: null,
};

export const useProjectStore = create<ProjectState & ProjectActions>()(
  persist(
    (set, get) => ({
      ...initialState,

      createProject: (name) => {
        const sceneStore = useSceneStore.getState();
        const videoStore = useVideoStore.getState();
        const audioStore = useAudioStore.getState();

        const now = Date.now();
        const project: Project = {
          id: createProjectId(),
          name,
          createdAt: now,
          updatedAt: now,
          version: PROJECT_VERSION,
          scenes: sceneStore.scenes,
          globalSettings: {
            video: {
              brightness: videoStore.brightness,
              contrast: videoStore.contrast,
              saturation: videoStore.saturation,
              blur: videoStore.blur,
              vignette: videoStore.vignette,
              faceLight: videoStore.faceLight,
              virtualBackground: videoStore.virtualBackground,
            },
            audio: {
              gain: audioStore.gain,
              noiseSuppression: audioStore.noiseSuppression,
              echoCancellation: audioStore.echoCancellation,
              autoGainControl: audioStore.autoGainControl,
              lowCut: audioStore.lowCut,
              midBoost: audioStore.midBoost,
              highBoost: audioStore.highBoost,
            },
          },
        };

        const projectListItem: ProjectListItem = {
          id: project.id,
          name: project.name,
          updatedAt: project.updatedAt,
          sceneCount: project.scenes.length,
        };

        set((state) => ({
          currentProject: project,
          projects: [...state.projects, projectListItem],
          isDirty: false,
          lastSavedAt: now,
        }));

        // Save to localStorage
        localStorage.setItem(`${STORAGE_KEY_PROJECTS}_${project.id}`, JSON.stringify(project));

        return project;
      },

      loadProject: (id) => {
        const stored = localStorage.getItem(`${STORAGE_KEY_PROJECTS}_${id}`);
        if (!stored) return false;

        try {
          const project: Project = JSON.parse(stored);
          const sceneStore = useSceneStore.getState();
          const videoStore = useVideoStore.getState();
          const audioStore = useAudioStore.getState();

          // Load scenes
          sceneStore.scenes.forEach(() => {}); // Clear reference
          set(() => ({})); // Trigger update

          // Apply global settings
          videoStore.updateSettings(project.globalSettings.video);
          videoStore.updateVirtualBackground(project.globalSettings.video.virtualBackground);
          audioStore.updateSettings(project.globalSettings.audio);

          set({
            currentProject: project,
            isDirty: false,
            lastSavedAt: project.updatedAt,
          });

          return true;
        } catch {
          console.error('Failed to load project');
          return false;
        }
      },

      saveProject: () => {
        const { currentProject } = get();
        if (!currentProject) return;

        const sceneStore = useSceneStore.getState();
        const videoStore = useVideoStore.getState();
        const audioStore = useAudioStore.getState();

        const now = Date.now();
        const updatedProject: Project = {
          ...currentProject,
          updatedAt: now,
          scenes: sceneStore.scenes,
          globalSettings: {
            video: {
              brightness: videoStore.brightness,
              contrast: videoStore.contrast,
              saturation: videoStore.saturation,
              blur: videoStore.blur,
              vignette: videoStore.vignette,
              faceLight: videoStore.faceLight,
              virtualBackground: videoStore.virtualBackground,
            },
            audio: {
              gain: audioStore.gain,
              noiseSuppression: audioStore.noiseSuppression,
              echoCancellation: audioStore.echoCancellation,
              autoGainControl: audioStore.autoGainControl,
              lowCut: audioStore.lowCut,
              midBoost: audioStore.midBoost,
              highBoost: audioStore.highBoost,
            },
          },
        };

        localStorage.setItem(
          `${STORAGE_KEY_PROJECTS}_${currentProject.id}`,
          JSON.stringify(updatedProject)
        );

        set((state) => ({
          currentProject: updatedProject,
          projects: state.projects.map((p) =>
            p.id === currentProject.id
              ? { ...p, updatedAt: now, sceneCount: sceneStore.scenes.length }
              : p
          ),
          isDirty: false,
          lastSavedAt: now,
        }));
      },

      renameProject: (id, name) => {
        set((state) => ({
          projects: state.projects.map((p) =>
            p.id === id ? { ...p, name } : p
          ),
          currentProject:
            state.currentProject?.id === id
              ? { ...state.currentProject, name }
              : state.currentProject,
        }));

        const stored = localStorage.getItem(`${STORAGE_KEY_PROJECTS}_${id}`);
        if (stored) {
          const project = JSON.parse(stored);
          project.name = name;
          localStorage.setItem(`${STORAGE_KEY_PROJECTS}_${id}`, JSON.stringify(project));
        }
      },

      deleteProject: (id) => {
        localStorage.removeItem(`${STORAGE_KEY_PROJECTS}_${id}`);

        set((state) => ({
          projects: state.projects.filter((p) => p.id !== id),
          currentProject:
            state.currentProject?.id === id ? null : state.currentProject,
        }));
      },

      exportProject: () => {
        const { currentProject } = get();
        if (!currentProject) return '';

        const sceneStore = useSceneStore.getState();
        const videoStore = useVideoStore.getState();
        const audioStore = useAudioStore.getState();

        const exportData: Project = {
          ...currentProject,
          scenes: sceneStore.scenes,
          globalSettings: {
            video: {
              brightness: videoStore.brightness,
              contrast: videoStore.contrast,
              saturation: videoStore.saturation,
              blur: videoStore.blur,
              vignette: videoStore.vignette,
              faceLight: videoStore.faceLight,
              virtualBackground: videoStore.virtualBackground,
            },
            audio: {
              gain: audioStore.gain,
              noiseSuppression: audioStore.noiseSuppression,
              echoCancellation: audioStore.echoCancellation,
              autoGainControl: audioStore.autoGainControl,
              lowCut: audioStore.lowCut,
              midBoost: audioStore.midBoost,
              highBoost: audioStore.highBoost,
            },
          },
        };

        return JSON.stringify(exportData, null, 2);
      },

      importProject: (json) => {
        try {
          const project: Project = JSON.parse(json);

          if (!project.id || !project.name || !project.version) {
            throw new Error('Invalid project format');
          }

          // Generate new ID for imported project
          const newId = createProjectId();
          const now = Date.now();

          const importedProject: Project = {
            ...project,
            id: newId,
            name: `${project.name} (импорт)`,
            createdAt: now,
            updatedAt: now,
          };

          const projectListItem: ProjectListItem = {
            id: importedProject.id,
            name: importedProject.name,
            updatedAt: importedProject.updatedAt,
            sceneCount: importedProject.scenes.length,
          };

          localStorage.setItem(
            `${STORAGE_KEY_PROJECTS}_${newId}`,
            JSON.stringify(importedProject)
          );

          set((state) => ({
            projects: [...state.projects, projectListItem],
          }));

          return true;
        } catch (error) {
          console.error('Failed to import project:', error);
          return false;
        }
      },

      setDirty: (dirty) =>
        set({ isDirty: dirty }),

      refreshProjectList: () => {
        const projects: ProjectListItem[] = [];
        for (let i = 0; i < localStorage.length; i++) {
          const key = localStorage.key(i);
          if (key?.startsWith(STORAGE_KEY_PROJECTS + '_')) {
            try {
              const data = localStorage.getItem(key);
              if (data) {
                const project: Project = JSON.parse(data);
                projects.push({
                  id: project.id,
                  name: project.name,
                  updatedAt: project.updatedAt,
                  sceneCount: project.scenes.length,
                });
              }
            } catch {
              // Skip invalid entries
            }
          }
        }
        set({ projects: projects.sort((a, b) => b.updatedAt - a.updatedAt) });
      },
    }),
    {
      name: 'kazarian-project-state',
      partialize: (state) => ({
        projects: state.projects,
      }),
    }
  )
);
