import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { AudioState, AudioSettings } from '@/types';
import { DEFAULT_AUDIO_SETTINGS } from '@/types';

interface AudioActions {
  updateSettings: (settings: Partial<AudioSettings>) => void;
  setDevice: (deviceId: string) => void;
  setDevices: (devices: MediaDeviceInfo[]) => void;
  toggleMute: () => void;
  setMonitorLevel: (level: number) => void;
  toggleMonitoring: () => void;
  setRecordingAudio: (ctx: AudioContext | null, dest: MediaStreamAudioDestinationNode | null) => void;
  reset: () => void;
}

// Non-persisted state for recording audio nodes
interface RecordingAudioState {
  recordingAudioContext: AudioContext | null;
  recordingAudioDestination: MediaStreamAudioDestinationNode | null;
}

const initialState: AudioState & RecordingAudioState = {
  ...DEFAULT_AUDIO_SETTINGS,
  selectedDeviceId: '',
  devices: [],
  isMuted: false,
  monitorLevel: 0,
  isMonitoring: false,
  recordingAudioContext: null,
  recordingAudioDestination: null,
};

export const useAudioStore = create<AudioState & RecordingAudioState & AudioActions>()(
  persist(
    (set) => ({
      ...initialState,

      updateSettings: (settings) =>
        set((state) => ({
          ...state,
          ...settings,
        })),

      setDevice: (deviceId) =>
        set({ selectedDeviceId: deviceId }),

      setDevices: (devices) =>
        set((state) => {
          const newState: Partial<AudioState> = { devices };
          if (!state.selectedDeviceId && devices.length > 0) {
            newState.selectedDeviceId = devices[0].deviceId;
          }
          return newState;
        }),

      toggleMute: () =>
        set((state) => ({ isMuted: !state.isMuted })),

      setMonitorLevel: (level) =>
        set({ monitorLevel: level }),

      toggleMonitoring: () =>
        set((state) => ({ isMonitoring: !state.isMonitoring })),

      setRecordingAudio: (ctx, dest) =>
        set({ recordingAudioContext: ctx, recordingAudioDestination: dest }),

      reset: () =>
        set({
          ...DEFAULT_AUDIO_SETTINGS,
          isMuted: false,
          monitorLevel: 0,
          isMonitoring: false,
          recordingAudioContext: null,
          recordingAudioDestination: null,
        }),
    }),
    {
      name: 'kazarian-audio-settings',
      partialize: (state) => ({
        gain: state.gain,
        noiseSuppression: state.noiseSuppression,
        echoCancellation: state.echoCancellation,
        autoGainControl: state.autoGainControl,
        lowCut: state.lowCut,
        midBoost: state.midBoost,
        highBoost: state.highBoost,
      }),
    }
  )
);
