import React, { useState } from 'react';
import { Plus, Trash2, ExternalLink, Eye, EyeOff } from 'lucide-react';
import { clsx } from 'clsx';
import { Button, Select, Slider, Modal, ModalBody, ModalFooter } from '@/components/common';
import { useStreamStore, selectActiveConfig } from '@/stores';
import { DEFAULT_RTMP_CONFIG } from '@/types';
import type { StreamPlatform, StreamResolution } from '@/types';

export const StreamTab: React.FC = () => {
  const {
    configs,
    activeConfigId,
    addConfig,
    updateConfig,
    deleteConfig,
    setActiveConfig,
    updatePlatformUrl,
  } = useStreamStore();

  const [showStreamKey, setShowStreamKey] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newConfigName, setNewConfigName] = useState('');

  const activeConfig = selectActiveConfig(useStreamStore.getState());

  const handleAddConfig = () => {
    if (newConfigName.trim()) {
      addConfig({
        ...DEFAULT_RTMP_CONFIG,
        name: newConfigName.trim(),
      });
      setNewConfigName('');
      setIsAddModalOpen(false);
    }
  };

  const platformOptions = [
    { value: 'youtube', label: 'YouTube Live' },
    { value: 'twitch', label: 'Twitch' },
    { value: 'vk', label: 'VK Video' },
    { value: 'facebook', label: 'Facebook Live' },
    { value: 'custom', label: 'Другой (RTMP)' },
  ];

  const resolutionOptions = [
    { value: '720p', label: '720p (1280x720)' },
    { value: '1080p', label: '1080p (1920x1080)' },
    { value: '1440p', label: '1440p (2560x1440)' },
    { value: '4k', label: '4K (3840x2160)' },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold text-white">Стриминг</h3>
        <Button
          size="sm"
          onClick={() => setIsAddModalOpen(true)}
          leftIcon={<Plus size={16} />}
        >
          Добавить
        </Button>
      </div>

      {/* Config Tabs */}
      {configs.length > 0 && (
        <div className="flex gap-2 overflow-x-auto pb-2">
          {configs.map((config) => (
            <button
              key={config.id}
              onClick={() => setActiveConfig(config.id)}
              className={clsx(
                'px-3 py-1.5 rounded-full text-sm whitespace-nowrap transition-colors',
                activeConfigId === config.id
                  ? 'bg-blue-600 text-white'
                  : 'bg-slate-800 text-slate-400 hover:text-white'
              )}
            >
              {config.name}
            </button>
          ))}
        </div>
      )}

      {activeConfig ? (
        <div className="space-y-4">
          {/* Platform */}
          <Select
            label="Платформа"
            value={activeConfig.platform}
            options={platformOptions}
            onChange={(v) => updatePlatformUrl(activeConfig.id, v as StreamPlatform)}
          />

          {/* RTMP URL */}
          <div>
            <label className="text-xs font-medium text-slate-400 uppercase mb-1 block">
              RTMP Server URL
            </label>
            <input
              type="text"
              value={activeConfig.url}
              onChange={(e) => updateConfig(activeConfig.id, { url: e.target.value })}
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm text-white focus:border-blue-500 outline-none font-mono"
              placeholder="rtmp://..."
            />
          </div>

          {/* Stream Key */}
          <div>
            <label className="text-xs font-medium text-slate-400 uppercase mb-1 block">
              Stream Key
            </label>
            <div className="relative">
              <input
                type={showStreamKey ? 'text' : 'password'}
                value={activeConfig.streamKey}
                onChange={(e) => updateConfig(activeConfig.id, { streamKey: e.target.value })}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 pr-10 text-sm text-white focus:border-blue-500 outline-none font-mono"
                placeholder="Введите ключ трансляции"
              />
              <button
                type="button"
                onClick={() => setShowStreamKey(!showStreamKey)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white"
              >
                {showStreamKey ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
            <p className="text-[10px] text-slate-500 mt-1">
              * Никогда не делитесь своим ключом трансляции
            </p>
          </div>

          {/* Quality Settings */}
          <Select
            label="Разрешение"
            value={activeConfig.resolution}
            options={resolutionOptions}
            onChange={(v) => updateConfig(activeConfig.id, { resolution: v as StreamResolution })}
          />

          <Slider
            label="Битрейт"
            value={activeConfig.bitrate}
            min={1000}
            max={10000}
            step={500}
            unit=" kbps"
            onChange={(v) => updateConfig(activeConfig.id, { bitrate: v })}
          />

          {/* Actions */}
          <div className="flex gap-2 pt-4">
            <Button
              variant="danger"
              size="sm"
              onClick={() => {
                if (confirm('Удалить эту конфигурацию?')) {
                  deleteConfig(activeConfig.id);
                }
              }}
              leftIcon={<Trash2 size={16} />}
            >
              Удалить
            </Button>
          </div>
        </div>
      ) : (
        <div className="text-center py-8 text-slate-400">
          <p className="mb-2">Нет конфигураций стриминга</p>
          <p className="text-xs">
            Добавьте конфигурацию для YouTube, Twitch или другой платформы
          </p>
        </div>
      )}

      {/* Info */}
      <div className="bg-slate-800 p-4 rounded-lg space-y-3">
        <h4 className="text-sm font-medium text-white">Как стримить</h4>
        <ol className="text-xs text-slate-400 space-y-2 list-decimal list-inside">
          <li>Введите RTMP URL и Stream Key вашей платформы</li>
          <li>Откройте OBS Studio или другой стриминг-софт</li>
          <li>Используйте "Захват окна" для захвата этого приложения</li>
          <li>Начните трансляцию в OBS</li>
        </ol>

        <a
          href="https://obsproject.com/download"
          target="_blank"
          rel="noopener noreferrer"
          className="inline-flex items-center gap-1 text-xs text-blue-400 hover:text-blue-300"
        >
          Скачать OBS Studio
          <ExternalLink size={12} />
        </a>
      </div>

      {/* Add Config Modal */}
      <Modal
        isOpen={isAddModalOpen}
        onClose={() => setIsAddModalOpen(false)}
        title="Новая конфигурация"
        size="sm"
      >
        <ModalBody>
          <input
            type="text"
            placeholder="Название (напр. YouTube канал)"
            value={newConfigName}
            onChange={(e) => setNewConfigName(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAddConfig()}
            className="w-full bg-slate-800 border border-slate-700 rounded-lg px-4 py-3 text-white placeholder:text-slate-500 focus:border-blue-500 outline-none"
            autoFocus
          />
        </ModalBody>
        <ModalFooter>
          <Button variant="ghost" onClick={() => setIsAddModalOpen(false)}>
            Отмена
          </Button>
          <Button onClick={handleAddConfig} disabled={!newConfigName.trim()}>
            Добавить
          </Button>
        </ModalFooter>
      </Modal>
    </div>
  );
};
