import { useEffect, useRef, useCallback } from 'react';
import { useOverlayStore, useRecordingStore } from '@/stores';
import { useSpeechRecognition } from './useSpeechRecognition';

/**
 * Hook that manages live subtitles during recording.
 * Connects speech recognition to the subtitles overlay.
 */
export function useSubtitles() {
  const subtitles = useOverlayStore((s) => s.subtitles);
  const updateSubtitles = useOverlayStore((s) => s.updateSubtitles);
  const isRecording = useRecordingStore((s) => s.isRecording);

  const clearTimeoutRef = useRef<number | null>(null);

  // Clear subtitle text after a delay
  const clearSubtitleAfterDelay = useCallback(() => {
    if (clearTimeoutRef.current) {
      clearTimeout(clearTimeoutRef.current);
    }

    clearTimeoutRef.current = window.setTimeout(() => {
      updateSubtitles({ currentText: '' });
    }, 3000); // Clear after 3 seconds of silence
  }, [updateSubtitles]);

  // Handle speech recognition results
  const handleResult = useCallback((transcript: string, isFinal: boolean) => {
    // Update the current text
    updateSubtitles({ currentText: transcript });

    // If it's a final result, schedule clearing
    if (isFinal) {
      clearSubtitleAfterDelay();
    }
  }, [updateSubtitles, clearSubtitleAfterDelay]);

  const {
    isListening,
    start: startRecognition,
    stop: stopRecognition,
    isSupported,
    error,
  } = useSpeechRecognition({
    language: subtitles.language,
    continuous: true,
    interimResults: true,
    onResult: handleResult,
  });

  // Auto-start/stop based on recording state and subtitles enabled
  useEffect(() => {
    if (subtitles.enabled && isRecording && isSupported) {
      startRecognition();
    } else {
      stopRecognition();
      // Clear subtitles when stopping
      updateSubtitles({ currentText: '' });
    }

    return () => {
      if (clearTimeoutRef.current) {
        clearTimeout(clearTimeoutRef.current);
      }
    };
  }, [subtitles.enabled, isRecording, isSupported, startRecognition, stopRecognition, updateSubtitles]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (clearTimeoutRef.current) {
        clearTimeout(clearTimeoutRef.current);
      }
      stopRecognition();
    };
  }, [stopRecognition]);

  return {
    isListening,
    isSupported,
    error,
  };
}
