import { useEffect, useRef, useCallback } from 'react';
import { useOverlayStore, useRecordingStore } from '@/stores';
import { useSoundEffects } from './useSoundEffects';

/**
 * Hook to automatically show/hide lower third during recording
 * - Shows after autoShowDelay (default 30s)
 * - Stays visible for autoShowDuration (default 30s)
 * - Repeats every autoShowInterval (default 10 min)
 * - Plays sound effect when appearing
 */
export function useLowerThirdAutoShow() {
  const isRecording = useRecordingStore((s) => s.isRecording);
  const lowerThird = useOverlayStore((s) => s.lowerThird);
  const updateLowerThird = useOverlayStore((s) => s.updateLowerThird);

  const { play: playSound } = useSoundEffects({ volume: 0.7 });

  const showTimeoutRef = useRef<number | null>(null);
  const hideTimeoutRef = useRef<number | null>(null);
  const intervalRef = useRef<number | null>(null);
  const recordingStartRef = useRef<number>(0);

  // Show lower third with sound
  const showLowerThird = useCallback(() => {
    updateLowerThird({ visible: true });

    // Play sound effect
    if (lowerThird.soundEffect) {
      playSound(lowerThird.soundEffect);
    }

    // Schedule hide
    hideTimeoutRef.current = window.setTimeout(() => {
      updateLowerThird({ visible: false });
    }, lowerThird.autoShowDuration);
  }, [lowerThird.soundEffect, lowerThird.autoShowDuration, playSound, updateLowerThird]);

  // Clear all timers
  const clearAllTimers = useCallback(() => {
    if (showTimeoutRef.current) {
      clearTimeout(showTimeoutRef.current);
      showTimeoutRef.current = null;
    }
    if (hideTimeoutRef.current) {
      clearTimeout(hideTimeoutRef.current);
      hideTimeoutRef.current = null;
    }
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
  }, []);

  // Start auto-show sequence
  const startAutoShow = useCallback(() => {
    if (!lowerThird.autoShow) return;

    recordingStartRef.current = Date.now();

    // First show after delay
    showTimeoutRef.current = window.setTimeout(() => {
      showLowerThird();

      // Then repeat at interval
      intervalRef.current = window.setInterval(() => {
        showLowerThird();
      }, lowerThird.autoShowInterval);
    }, lowerThird.autoShowDelay);
  }, [lowerThird.autoShow, lowerThird.autoShowDelay, lowerThird.autoShowInterval, showLowerThird]);

  // Effect to handle recording state changes
  useEffect(() => {
    if (isRecording && lowerThird.autoShow) {
      // Recording started - begin auto-show sequence
      startAutoShow();
    } else {
      // Recording stopped - clear timers and hide
      clearAllTimers();
      if (!isRecording) {
        updateLowerThird({ visible: false });
      }
    }

    return () => {
      clearAllTimers();
    };
  }, [isRecording, lowerThird.autoShow, startAutoShow, clearAllTimers, updateLowerThird]);

  // Manual show (for testing or manual trigger)
  const triggerShow = useCallback(() => {
    showLowerThird();
  }, [showLowerThird]);

  return {
    triggerShow,
    isAutoShowEnabled: lowerThird.autoShow,
  };
}
