export type Position = 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right' | 'top' | 'bottom' | 'center';
export type LowerThirdStyle = 'modern' | 'neon' | 'glass' | 'minimal';

export interface LowerThird {
  visible: boolean;
  text1: string;
  text2: string;
  style: LowerThirdStyle;
  position: 'left' | 'center' | 'right';
  backgroundColor: string;
  textColor: string;
  accentColor: string;
  // Auto-show settings
  autoShow: boolean;
  autoShowDelay: number; // ms before first show (default 30000 = 30s)
  autoShowDuration: number; // ms to stay visible (default 30000 = 30s)
  autoShowInterval: number; // ms between shows (default 600000 = 10min)
  soundEffect: string | null; // sound effect id to play
}

export interface Ticker {
  visible: boolean;
  text: string;
  speed: number;
  position: 'top' | 'bottom';
  backgroundColor: string;
  textColor: string;
  fontSize: number;
  // Auto-show settings
  autoShow: boolean;
  autoShowDelay: number; // ms before first show
  autoShowDuration: number; // ms to stay visible
  autoShowInterval: number; // ms between shows
  soundEffect: string | null;
}

export interface Logo {
  visible: boolean;
  url: string | null;
  text: string;
  opacity: number;
  position: Position;
  scale: number;
}

export interface Subtitles {
  enabled: boolean;
  fontSize: number;
  backgroundColor: string;
  textColor: string;
  position: 'top' | 'center' | 'bottom';
  maxWidth: number;
  language: string;
  currentText: string; // Current spoken text for display
}

export interface AdOverlay {
  id: string;
  visible: boolean;
  template: 'pill' | 'modern' | 'elegant' | 'cyber' | 'banner';
  title: string;
  subtitle: string;
  imageUrl: string | null;
  position: Position;
  animation: 'slide' | 'fade' | 'scale' | 'flip';
  backgroundColor: string;
  textColor: string;
  accentColor: string;
  duration: number;
  width: number;
  borderRadius: number;
}

export interface OverlayState {
  lowerThird: LowerThird;
  ticker: Ticker;
  logo: Logo;
  subtitles: Subtitles;
  ads: AdOverlay[];
  activeAdId: string | null;
}

